# === ENVIRONMENT VALIDATION ===
def _env_bool_early(name: str, default: bool = False) -> bool:
    val = os.getenv(name)
    if val is None:
        return default
    return val.strip().lower() in {"1", "true", "yes", "on"}


def validate_required_env_vars():
    """Validate environment variables according to deployment mode (Render / local)."""
    missing: List[str] = []

    if _env_bool_early("USE_SUPABASE", False):
        if not (os.getenv("SUPABASE_URL") or "").strip():
            missing.append("SUPABASE_URL")
        supabase_key = (
            os.getenv("SUPABASE_SERVICE_ROLE_KEY")
            or os.getenv("SUPABASE_SERVICE_KEY")
            or os.getenv("SUPABASE_ANON_KEY")
            or os.getenv("SUPABASE_KEY")
        )
        if not (supabase_key or "").strip():
            missing.append("SUPABASE_KEY (ou SUPABASE_SERVICE_KEY / SUPABASE_ANON_KEY)")

    if _env_bool_early("ENABLE_GEMINI", False) and not (os.getenv("GEMINI_API_KEY") or "").strip():
        missing.append("GEMINI_API_KEY")

    if missing:
        raise EnvironmentError(
            f"[ERROR] CRITICAL: Missing required environment variables: {', '.join(missing)}\n"
            f"Configure-les dans le dashboard Render (Environment) ou dans votre fichier .env"
        )
    print("[OK] Required environment variables configured for current deployment mode")

# === INPUT VALIDATION ===
VALID_SYMBOL_PATTERN = re.compile(r'^[A-Z0-9_]{2,20}$')
VALID_TIMEFRAMES = {'M1', 'M5', 'M15', 'M30', 'H1', 'H4', 'D1', 'W1'}

def validate_symbol(symbol: str) -> bool:
    """Validate symbol format"""
    return bool(symbol and VALID_SYMBOL_PATTERN.match(symbol))

def validate_timeframe(timeframe: str) -> bool:
    """Validate timeframe is known"""
    return timeframe in VALID_TIMEFRAMES

# --- Supabase config helpers ---
def _get_supabase_config(strict: bool = True) -> Tuple[str, str]:
    """
    Retourne (SUPABASE_URL, SUPABASE_KEY).
    En mode strict, refuse les valeurs par défaut silencieuses pour éviter d'écrire dans le mauvais projet.
    IMPORTANT: Si USE_SUPABASE=false, retourne ("", "") pour désactiver tous les appels Supabase.
    """
    # Bloquer complètement si USE_SUPABASE=false
    if not _env_bool("USE_SUPABASE", False):
        return "", ""

    supabase_url = (os.getenv("SUPABASE_URL") or "").strip()
    supabase_key = (
        os.getenv("SUPABASE_SERVICE_ROLE_KEY")
        or os.getenv("SUPABASE_SERVICE_KEY")
        or os.getenv("SUPABASE_ANON_KEY")
        or ""
    ).strip()

    if strict and (not supabase_url or not supabase_key):
        raise RuntimeError("Supabase non configuré (SUPABASE_URL et SUPABASE_*KEY requis)")

    return supabase_url, supabase_key


def _supabase_credentials_ready() -> bool:
    """
    True si URL + clé service/anon présentes (sans lever d'exception).
    IMPORTANT: Retourne toujours False si USE_SUPABASE=false.
    """
    # Bloquer complètement si USE_SUPABASE=false
    if not _env_bool("USE_SUPABASE", False):
        return False

    url = (os.getenv("SUPABASE_URL") or "").strip()
    key = (
        os.getenv("SUPABASE_SERVICE_ROLE_KEY")
        or os.getenv("SUPABASE_SERVICE_KEY")
        or os.getenv("SUPABASE_ANON_KEY")
        or ""
    ).strip()
    return bool(url and key)


