RISK_PARAMS_360 = {
    "scalping_risk_pct": 1.0,
    "swing_risk_pct": 1.5,
    "max_total_risk_pct": 4.0,
    "max_scalp_trades": 5,
    "max_swing_trades": 3,
    "cooldown_after_sl_min": 15,
    "max_dd_pct_daily": 5.0,
    "account_balance": 10000.0,
}

SCORE_THRESHOLDS_360 = {"scalping": 70, "swing": 75}


@dataclass
class TradeSignal360:
    signal_id: str
    timestamp_utc: str
    symbol: str
    mode: str
    action: str
    entry_price: float
    stop_loss: float
    take_profit_1: float
    take_profit_2: float
    take_profit_3: float
    lot_size: float
    risk_percent: float
    risk_reward: float
    confluence_score: int
    confidence: str
    justification: list
    invalidation: str
    expires_in_min: int


class TradingState360:
    def __init__(self):
        self.open_trades: dict = {}
        self.daily_pnl: float = 0.0
        self.cooldown_symbols: dict = {}
        self.total_risk_pct: float = 0.0

    def is_in_cooldown(self, symbol: str) -> bool:
        ts = self.cooldown_symbols.get(symbol)
        return bool(ts and time.time() < ts)

    def can_open_trade(self, mode: str) -> bool:
        scalp_count = sum(1 for t in self.open_trades.values() if t.get("mode") == "SCALPING")
        swing_count = sum(1 for t in self.open_trades.values() if t.get("mode") == "SWING")
        if mode == "SCALPING" and scalp_count >= RISK_PARAMS_360["max_scalp_trades"]:
            return False
        if mode == "SWING" and swing_count >= RISK_PARAMS_360["max_swing_trades"]:
            return False
        if self.total_risk_pct >= RISK_PARAMS_360["max_total_risk_pct"]:
            return False
        if abs(self.daily_pnl) / RISK_PARAMS_360["account_balance"] * 100 >= RISK_PARAMS_360["max_dd_pct_daily"]:
            return False
        return True


state360 = TradingState360()


def _detect_symbol_type_360(symbol: str) -> str:
    symbol = symbol.upper()
    volatility_keywords = ["V10", "V25", "V50", "V75", "V100", "BOOM", "CRASH", "STEP", "RANGE"]
    if any(k in symbol for k in volatility_keywords):
        return "VOLATILITY"
    major_pairs = ["EURUSD", "GBPUSD", "USDJPY", "USDCHF", "AUDUSD", "USDCAD", "NZDUSD"]
    if symbol in major_pairs:
        return "FOREX_MAJOR"
    if len(symbol) == 6 and symbol.isalpha():
        return "FOREX_CROSS"
    if any(k in symbol for k in ["SPX", "NAS", "DAX", "DOW", "CAC", "FTSE"]):
        return "INDEX"
    return "FOREX_EXOTIC"


def _calc_lot_size_360(risk_pct: float, sl_pips: float, symbol_type: str) -> float:
    balance = RISK_PARAMS_360["account_balance"]
    risk_usd = balance * (risk_pct / 100)
    pip_value = 10.0
    if symbol_type == "VOLATILITY":
        pip_value = 0.10
    elif symbol_type == "INDEX":
        pip_value = 1.0
    if sl_pips <= 0:
        return 0.01
    lot = risk_usd / (sl_pips * pip_value)
    return round(max(0.01, min(lot, 10.0)), 2)


def _confidence_label_360(score: int) -> str:
    if score >= 85:
        return "HIGH"
    if score >= 75:
        return "MEDIUM"
    return "LOW"


def _analyze_scalping_360(data: dict) -> tuple[str, list, list]:
    tf_m5 = data.get("timeframes", {}).get("M5", {})
    tf_m15 = data.get("timeframes", {}).get("M15", {})
    tf_h1 = data.get("timeframes", {}).get("H1", {})
    meta = data.get("meta", {})
    score = int(meta.get("confluence_score", 0) or 0)

    buy_conditions: list[str] = []
    sell_conditions: list[str] = []
    rejections: list[str] = []

    h1_bias = tf_h1.get("ema_alignment", "")
    if h1_bias == "BULLISH_STACK":
        buy_conditions.append("Biais H1 BULLISH (EMA stack haussier)")
    elif h1_bias == "BEARISH_STACK":
        sell_conditions.append("Biais H1 BEARISH (EMA stack baissier)")
    else:
        rejections.append(f"Biais H1 ambigu ({h1_bias}) — pas de direction claire")

    m15_align = tf_m15.get("ema_alignment", "")
    if m15_align == "BULLISH_STACK":
        buy_conditions.append("EMA 8>21>50 sur M15 (stack haussier confirmé)")
    elif m15_align == "BEARISH_STACK":
        sell_conditions.append("EMA 8<21<50 sur M15 (stack baissier confirmé)")
    else:
        rejections.append(f"Alignement EMA M15 non idéal ({m15_align})")

    price_vs_ema21 = tf_m5.get("price_vs_ema21", "")
    if price_vs_ema21 == "ABOVE":
        buy_conditions.append("Prix au-dessus EMA21 M5 (momentum local haussier)")
    elif price_vs_ema21 == "BELOW":
        sell_conditions.append("Prix sous EMA21 M5 (momentum local baissier)")

    rsi_m5 = float(tf_m5.get("rsi_14", 50) or 50)
    if 40 <= rsi_m5 <= 65:
        buy_conditions.append(f"RSI M5 = {rsi_m5:.1f} (zone favorable BUY)")
    elif 35 <= rsi_m5 <= 60:
        sell_conditions.append(f"RSI M5 = {rsi_m5:.1f} (zone favorable SELL)")
    elif rsi_m5 > 70:
        rejections.append(f"RSI M5 suracheté ({rsi_m5:.1f}) — risque retournement")
    elif rsi_m5 < 30:
        rejections.append(f"RSI M5 survendu ({rsi_m5:.1f}) — risque retournement")

    macd_hist = float(tf_m5.get("macd_hist", 0) or 0)
    macd_cross = str(tf_m5.get("macd_cross", "") or "")
    if macd_hist > 0 or "BULLISH" in macd_cross:
        buy_conditions.append(f"MACD M5 haussier (hist={macd_hist:.5f}, cross={macd_cross})")
    elif macd_hist < 0 or "BEARISH" in macd_cross:
        sell_conditions.append(f"MACD M5 baissier (hist={macd_hist:.5f})")

    candle = str(tf_m5.get("candle_type", "") or "")
    candle_confirm = bool(tf_m5.get("candle_confirmation", False))
    bullish = {"PIN_BAR_BULLISH", "ENGULFING_BULLISH", "HAMMER", "MORNING_STAR"}
    bearish = {"PIN_BAR_BEARISH", "ENGULFING_BEARISH", "SHOOTING_STAR", "EVENING_STAR"}
    if candle in bullish and candle_confirm:
        buy_conditions.append(f"Bougie trigger BUY : {candle} confirmée")
    elif candle in bearish and candle_confirm:
        sell_conditions.append(f"Bougie trigger SELL : {candle} confirmée")
    else:
        rejections.append(f"Pas de bougie trigger confirmée (type={candle})")

    if score < SCORE_THRESHOLDS_360["scalping"]:
        rejections.append(f"Score confluence insuffisant ({score} < {SCORE_THRESHOLDS_360['scalping']})")

    session = str(data.get("session", "") or "")
    good_sessions = ("LONDON", "NEW_YORK", "LONDON_NY_OVERLAP")
    if not any(s in session for s in good_sessions):
        rejections.append(f"Session non premium ({session})")
    else:
        buy_conditions.append(f"Session active : {session}")
        sell_conditions.append(f"Session active : {session}")

    if str(data.get("news_risk", "NONE") or "NONE") == "HIGH":
        rejections.append("News HIGH imminente — trading suspendu")

    if rejections:
        return "HOLD", [], rejections

    buy_score = len(buy_conditions)
    sell_score = len(sell_conditions)
    if buy_score >= 5 and buy_score > sell_score:
        return "BUY", buy_conditions, []
    if sell_score >= 5 and sell_score > buy_score:
        return "SELL", sell_conditions, []
    return "HOLD", [], [f"Conditions insuffisantes (BUY={buy_score}, SELL={sell_score})"]


def _analyze_swing_360(data: dict) -> tuple[str, list, list]:
    tf_h1 = data.get("timeframes", {}).get("H1", {})
    tf_h4 = data.get("timeframes", {}).get("H4", {})
    tf_d1 = data.get("timeframes", {}).get("D1", {})
    meta = data.get("meta", {})
    score = int(meta.get("confluence_score", 0) or 0)

    buy_conditions: list[str] = []
    sell_conditions: list[str] = []
    rejections: list[str] = []

    d1_align = tf_d1.get("ema_alignment", "")
    if d1_align == "BULLISH_STACK":
        buy_conditions.append("Tendance D1 BULLISH (EMA50 D1 montante)")
    elif d1_align == "BEARISH_STACK":
        sell_conditions.append("Tendance D1 BEARISH (EMA50 D1 descendante)")
    else:
        rejections.append(f"Tendance D1 non définie ({d1_align})")

    h4_phase = tf_h4.get("market_phase", data.get("market_phase", ""))
    structure = meta.get("market_structure", "")
    if "HH_HL" in structure or h4_phase == "TRENDING_UP":
        buy_conditions.append("Structure H4 haussière (HH+HL confirmés)")
    elif "LL_LH" in structure or h4_phase == "TRENDING_DOWN":
        sell_conditions.append("Structure H4 baissière (LL+LH confirmés)")
    else:
        rejections.append(f"Structure H4 ambiguë ({structure})")

    rsi_h1 = float(tf_h1.get("rsi_14", 50) or 50)
    if 40 <= rsi_h1 <= 60:
        buy_conditions.append(f"RSI H1 = {rsi_h1:.1f} (zone neutre-haussière)")
        sell_conditions.append(f"RSI H1 = {rsi_h1:.1f} (zone neutre-baissière)")
    else:
        rejections.append(f"RSI H1 hors zone optimale ({rsi_h1:.1f})")

    adx_h1 = float(tf_h1.get("adx_14", 0) or 0)
    if adx_h1 >= 20:
        buy_conditions.append(f"ADX H1 = {adx_h1:.1f} (tendance présente)")
        sell_conditions.append(f"ADX H1 = {adx_h1:.1f} (tendance présente)")
    else:
        rejections.append(f"ADX H1 trop faible ({adx_h1:.1f} < 20) — marché en range")

    if score < SCORE_THRESHOLDS_360["swing"]:
        rejections.append(f"Score insuffisant pour swing ({score} < {SCORE_THRESHOLDS_360['swing']})")

    if str(data.get("news_risk", "NONE") or "NONE") == "HIGH":
        rejections.append("News HIGH — trading swing suspendu")

    if rejections:
        return "HOLD", [], rejections

    buy_score = len(buy_conditions)
    sell_score = len(sell_conditions)
    if buy_score >= 5 and buy_score > sell_score:
        return "BUY", buy_conditions, []
    if sell_score >= 5 and sell_score > buy_score:
        return "SELL", sell_conditions, []
    return "HOLD", [], [f"Conditions swing insuffisantes (BUY={buy_score}, SELL={sell_score})"]


def _build_signal_360(data: dict, action: str, mode: str, justifications: list) -> TradeSignal360:
    symbol = str(data.get("symbol", "UNKNOWN") or "UNKNOWN")
    symbol_type = _detect_symbol_type_360(symbol)
    score = int(data.get("meta", {}).get("confluence_score", 70) or 70)

    tf_key = "M5" if mode == "SCALPING" else "H1"
    tf_ref = data.get("timeframes", {}).get(tf_key, {})

    entry = float(tf_ref.get("close", 0) or 0)
    atr = float(tf_ref.get("atr_14_pips", 10) or 10)
    sl_multiplier = 1.0 if mode == "SCALPING" else 1.5
    sl_pips = max(atr * sl_multiplier, 8.0)

    pip_val = 0.0001 if symbol_type not in {"VOLATILITY", "INDEX"} else 0.01
    if action == "BUY":
        sl = entry - sl_pips * pip_val
        tp1 = entry + sl_pips * 1.5 * pip_val
        tp2 = float(tf_ref.get("nearest_resist", entry + sl_pips * 2.0 * pip_val) or (entry + sl_pips * 2.0 * pip_val))
        tp3 = entry + sl_pips * 3.0 * pip_val
        invalidation = f"Clôture {tf_key} sous {sl:.5f} annule le setup"
    else:
        sl = entry + sl_pips * pip_val
        tp1 = entry - sl_pips * 1.5 * pip_val
        tp2 = float(tf_ref.get("nearest_support", entry - sl_pips * 2.0 * pip_val) or (entry - sl_pips * 2.0 * pip_val))
        tp3 = entry - sl_pips * 3.0 * pip_val
        invalidation = f"Clôture {tf_key} au-dessus {sl:.5f} annule le setup"

    rr = abs(tp1 - entry) / abs(sl - entry) if abs(sl - entry) > 0 else 0.0
    risk_pct = RISK_PARAMS_360["scalping_risk_pct"] if mode == "SCALPING" else RISK_PARAMS_360["swing_risk_pct"]
    lot = _calc_lot_size_360(risk_pct, sl_pips, symbol_type)
    expires = 15 if mode == "SCALPING" else 240

    return TradeSignal360(
        signal_id=str(uuid4()),
        timestamp_utc=datetime.now(timezone.utc).isoformat(),
        symbol=symbol,
        mode=mode,
        action=action,
        entry_price=round(entry, 5),
        stop_loss=round(sl, 5),
        take_profit_1=round(tp1, 5),
        take_profit_2=round(tp2, 5),
        take_profit_3=round(tp3, 5),
        lot_size=lot,
        risk_percent=risk_pct,
        risk_reward=round(rr, 2),
        confluence_score=score,
        confidence=_confidence_label_360(score),
        justification=justifications,
        invalidation=invalidation,
        expires_in_min=expires,
    )


async def process_analysis_360(data: dict) -> dict:
    symbol = str(data.get("symbol", "UNKNOWN") or "UNKNOWN")
    score = int(data.get("meta", {}).get("confluence_score", 0) or 0)
    logger.info(f"360° Analyse reçue → {symbol} | score={score}")

    if state360.is_in_cooldown(symbol):
        return {"status": "REJECTED", "reason": f"{symbol} en cooldown post-SL"}

    results: list[dict] = []

    if state360.can_open_trade("SCALPING"):
        s_action, s_just, s_rej = _analyze_scalping_360(data)
        if s_action != "HOLD":
            signal = _build_signal_360(data, s_action, "SCALPING", s_just)
            results.append({"status": "SIGNAL", **asdict(signal)})
        else:
            logger.info(f"360° SCALPING HOLD {symbol}: {'; '.join(s_rej[:2])}")

    if state360.can_open_trade("SWING"):
        sw_action, sw_just, sw_rej = _analyze_swing_360(data)
        if sw_action != "HOLD":
            signal = _build_signal_360(data, sw_action, "SWING", sw_just)
            results.append({"status": "SIGNAL", **asdict(signal)})
        else:
            logger.info(f"360° SWING HOLD {symbol}: {'; '.join(sw_rej[:2])}")

    if results:
        return {"status": "SIGNALS", "count": len(results), "signals": results}
    return {"status": "HOLD", "symbol": symbol, "score": score}


class Decision360Request(BaseModel):
    payload: Dict[str, Any]


@app.post("/decision360")
async def decision_360(req: Decision360Request):
    return await process_analysis_360(req.payload)


@app.websocket("/ws360")
async def websocket_360(websocket: WebSocket):
    await websocket.accept()
    client = websocket.client
    logger.info(f"360° WebSocket connectée: {client}")
    try:
        while True:
            msg = await websocket.receive_text()
            try:
                data = json.loads(msg)
            except Exception as e:
                await websocket.send_text(json.dumps({"status": "ERROR", "message": f"JSON invalide: {e}"}))
                continue
            result = await process_analysis_360(data)
            await websocket.send_text(json.dumps(result, ensure_ascii=False))
    except WebSocketDisconnect:
        logger.info(f"360° WebSocket déconnectée: {client}")

