# ÉTAT TEMPS RÉEL POUR LES SPIKES (Boom/Crash) - inspiré de SpikeSniperDeriv
_last_tick_price: Dict[str, float] = defaultdict(float)
_last_spike_info: Dict[str, Dict[str, Any]] = {}
SPIKE_THRESHOLD_POINTS: float = float(os.getenv("SPIKE_THRESHOLD_POINTS", "1.0"))
SPIKE_RECENT_WINDOW_SECONDS: int = int(os.getenv("SPIKE_RECENT_WINDOW_SECONDS", "5"))
_m5_line_tracking_state: Dict[str, Dict[str, Any]] = {}


def _safe_optional_float(value: Any) -> Optional[float]:
    try:
        if value is None:
            return None
        return float(value)
    except Exception:
        return None


def _extract_m5_levels_from_request(req: "DecisionRequest") -> Dict[str, Optional[float]]:
    """
    Extrait les niveaux M5 trackés depuis la requête.
    Supporte les champs plats + aliases dans chart_levels.
    """
    levels: Dict[str, Optional[float]] = {
        "uptrend_line": _safe_optional_float(getattr(req, "m5_uptrend_line", None)),
        "downtrend_line": _safe_optional_float(getattr(req, "m5_downtrend_line", None)),
        "buy_entry": _safe_optional_float(getattr(req, "m5_buy_entry_point", None)),
        "sell_entry": _safe_optional_float(getattr(req, "m5_sell_entry_point", None)),
        "pure_red_line": _safe_optional_float(getattr(req, "m5_pure_red_line", None)),
    }

    chart_levels = getattr(req, "chart_levels", None)
    if isinstance(chart_levels, dict):
        aliases = {
            "uptrend_line": ["m5_uptrend_line", "uptrend_line", "m5_uptrend", "uptrend"],
            "downtrend_line": ["m5_downtrend_line", "downtrend_line", "m5_downtrend", "downtrend"],
            "buy_entry": ["m5_buy_entry_point", "buy_entry_point", "m5_buy_entry", "buy_entry"],
            "sell_entry": ["m5_sell_entry_point", "sell_entry_point", "m5_sell_entry", "sell_entry"],
            "pure_red_line": ["m5_pure_red_line", "pure_red_line", "red_line", "ligne_rouge_pure"],
        }
        for key, key_aliases in aliases.items():
            if levels[key] is not None:
                continue
            for alias in key_aliases:
                if alias in chart_levels:
                    parsed = _safe_optional_float(chart_levels.get(alias))
                    if parsed is not None:
                        levels[key] = parsed
                        break
    return levels


def update_m5_line_tracking_from_request(req: "DecisionRequest") -> Dict[str, Any]:
    """
    Met à jour le tracking des lignes M5 et signale quand un ancien limit doit être remplacé.
    """
    symbol = (getattr(req, "symbol", None) or "").strip()
    if not symbol:
        return {
            "enabled": False,
            "reason": "missing_symbol",
            "should_replace_limit_order": False,
        }

    levels = _extract_m5_levels_from_request(req)
    previous = _m5_line_tracking_state.get(symbol, {})
    changed_fields: List[str] = []
    tolerance = float(os.getenv("M5_LINE_MOVE_TOLERANCE", "0.00001"))

    for key, new_value in levels.items():
        old_value = previous.get(key)
        if new_value is None:
            continue
        if old_value is None or abs(float(new_value) - float(old_value)) > tolerance:
            changed_fields.append(key)

    update_index = int(previous.get("update_index", 0))
    moved = len(changed_fields) > 0
    if moved:
        update_index += 1

    snapshot = {
        "symbol": symbol,
        "levels": levels,
        "changed_fields": changed_fields,
        "line_moved": moved,
        "should_replace_limit_order": moved and any(
            field in ("buy_entry", "sell_entry", "pure_red_line") for field in changed_fields
        ),
        "update_index": update_index,
        "tracked_at": datetime.now(timezone.utc).isoformat(),
        "tolerance": tolerance,
    }
    _m5_line_tracking_state[symbol] = {
        **levels,
        "update_index": update_index,
    }

    if moved:
        logger.info(
            "📐 M5 line tracking | %s moved=%s replace_limit=%s",
            symbol,
            ",".join(changed_fields),
            snapshot["should_replace_limit_order"],
        )
    return snapshot


def _enrich_response_payload_with_m5_tracking(
    response_payload: Dict[str, Any], tracking_info: Optional[Dict[str, Any]]
) -> Dict[str, Any]:
    """
    Injecte le tracking M5 dans metadata ET duplique des champs clés au top-level.

    Important: certains clients MT5 parsers sont "plats" (StringFind/ExtractJsonValue).
    On expose donc aussi:
    - should_replace_limit_order
    - line_moved
    - update_index
    - changed_fields
    - buy_entry / sell_entry / pure_red_line
    """
    if not tracking_info:
        return response_payload
    enriched = dict(response_payload or {})
    metadata = dict(enriched.get("metadata") or {})
    metadata["m5_line_tracking"] = tracking_info
    enriched["metadata"] = metadata

    # Flat keys for MT5 clients (best-effort)
    try:
        enriched["should_replace_limit_order"] = bool(tracking_info.get("should_replace_limit_order", False))
        enriched["line_moved"] = bool(tracking_info.get("line_moved", False))
        enriched["update_index"] = int(tracking_info.get("update_index") or 0)
        enriched["changed_fields"] = tracking_info.get("changed_fields") or []

        levels = tracking_info.get("levels") if isinstance(tracking_info.get("levels"), dict) else {}
        if isinstance(levels, dict):
            if levels.get("buy_entry") is not None:
                enriched["buy_entry"] = float(levels["buy_entry"])
            if levels.get("sell_entry") is not None:
                enriched["sell_entry"] = float(levels["sell_entry"])
            if levels.get("pure_red_line") is not None:
                enriched["pure_red_line"] = float(levels["pure_red_line"])
    except Exception:
        # Must not break response
        pass
    return enriched


def update_spike_state_from_request(req: "DecisionRequest") -> None:
    """
    Met à jour l'état temps réel de spike à partir d'une requête de décision.
    Logique simplifiée inspirée de SpikeSniperDeriv:
    - Boom: spike si diff >= SPIKE_THRESHOLD_POINTS
    - Crash: spike si diff <= -SPIKE_THRESHOLD_POINTS
    """
    try:
        sym = (req.symbol or "").strip()
        if not sym:
            return

        # Utiliser mid-price comme proxy du dernier prix
        last_price = None
        if req.bid is not None and req.ask is not None:
            last_price = (float(req.bid) + float(req.ask)) / 2.0
        elif req.bid is not None:
            last_price = float(req.bid)
        elif req.ask is not None:
            last_price = float(req.ask)

        if last_price is None or last_price <= 0:
            return

        prev = _last_tick_price[sym]
        _last_tick_price[sym] = last_price

        # Pas de comparaison possible au premier tick
        if prev <= 0:
            return

        diff = last_price - prev
        s_low = sym.lower()
        threshold = SPIKE_THRESHOLD_POINTS

        is_boom = "boom" in s_low
        is_crash = "crash" in s_low

        is_spike = False
        direction: Optional[str] = None

        if is_boom and diff >= threshold:
            is_spike = True
            direction = "BOOM"
        elif is_crash and diff <= -threshold:
            is_spike = True
            direction = "CRASH"

        if not is_spike:
            return

        info = {
            "time": datetime.utcnow(),
            "direction": direction,
            "diff_points": float(diff),
        }
        _last_spike_info[sym] = info
        logger.info(
            "🚨 Spike temps réel détecté | symbol=%s direction=%s diff=%.5f",
            sym,
            direction,
            diff,
        )
    except Exception as e:
        logger.warning("Erreur update_spike_state_from_request: %s", e)

