# ============================================================================
# ML Data Collection Models
# ============================================================================
def _ema_dir(ema_fast: Optional[float], ema_slow: Optional[float]) -> int:
    """Return +1 bullish, -1 bearish, 0 neutral from EMA fast/slow."""
    try:
        ef = float(ema_fast or 0.0)
        es = float(ema_slow or 0.0)
        if ef <= 0.0 or es <= 0.0:
            return 0
        if ef > es:
            return 1
        if ef < es:
            return -1
    except Exception:
        return 0
    return 0


def _mtf_dir_from_mt5(symbol: str, timeframe: str) -> int:
    """Directional bias from MT5 indicators on a timeframe."""
    try:
        ind = get_mt5_indicators(symbol, timeframe, count=260)
        if not ind:
            return 0
        # Prefer EMA 20/50 when available.
        d = _ema_dir(ind.get("ema_20"), ind.get("ema_50"))
        if d != 0:
            return d
        # Fallback to EMA 50/100 for slower frames.
        return _ema_dir(ind.get("ema_50"), ind.get("ema_100"))
    except Exception:
        return 0


def _ia_status_decide(tf_dirs: Dict[str, int], tf_weights: Dict[str, float]) -> Dict[str, Any]:
    """
    Logique de décision IA Status partagée entre compute_ia_status_v2 et _enrich_ia_status.

    Règles (par ordre de priorité) :
    1. gap pondéré BUY/SELL < 0.15  →  HOLD  (marché réellement indécis)
    2. M5 s'oppose à la majorité    →  HOLD  (vrai conflit micro vs macro)
    3. Majorité claire + M5 aligné  →  BUY/SELL  confiance 68–85%
    4. Majorité claire + M5 neutre  →  BUY/SELL  confiance 53–65%
       (pause normale, pas un retournement)
    """
    score_buy = 0.0
    score_sell = 0.0
    total_w = 0.0
    count_buy = count_sell = count_neutral = 0

    for tf, d in tf_dirs.items():
        w = tf_weights.get(tf, 0.0)
        total_w += w
        if d > 0:
            score_buy += w
            count_buy += 1
        elif d < 0:
            score_sell += w
            count_sell += 1
        else:
            count_neutral += 1

    if total_w > 0:
        score_buy /= total_w
        score_sell /= total_w

    gap = abs(score_buy - score_sell)
    majority_dir = 1 if score_buy > score_sell else (-1 if score_sell > score_buy else 0)
    m5 = tf_dirs.get("M5", 0)

    if gap < 0.15 or majority_dir == 0:
        # Marché indécis — HOLD
        action = "hold"
        confidence = 0.40 + gap * 0.30

    elif m5 != 0 and m5 != majority_dir:
        # M5 s'oppose activement à la majorité — vrai conflit, pas d'entrée
        action = "hold"
        confidence = 0.48 + gap * 0.10

    elif m5 == majority_dir:
        # M5 confirme la majorité — signal fort
        action = "buy" if majority_dir == 1 else "sell"
        count_aligned = count_buy if majority_dir == 1 else count_sell
        confidence = min(0.85, 0.68 + (count_aligned / 6.0) * 0.17)

    else:
        # M5 neutre sur une tendance H4/H1 claire — pause normale, pas retournement
        action = "buy" if majority_dir == 1 else "sell"
        count_aligned = count_buy if majority_dir == 1 else count_sell
        confidence = min(0.65, 0.53 + (count_aligned / 6.0) * 0.12)

    confidence = max(0.0, min(1.0, confidence))
    total_votes = count_buy + count_sell + count_neutral
    if action == "buy":
        aligned_count = count_buy
    elif action == "sell":
        aligned_count = count_sell
    else:
        aligned_count = max(count_buy, count_sell, count_neutral)
    alignment_score = min(1.0, aligned_count / max(total_votes, 1)) * 100.0

    return {
        "action": action,
        "confidence": confidence,
        "confidence_percent": round(confidence * 100.0, 1),
        "alignment_score": round(alignment_score, 1),
        "m5_direction": m5,
        "score_buy": round(score_buy, 3),
        "score_sell": round(score_sell, 3),
        "gap": round(gap, 3),
        "counts": {"buy": count_buy, "sell": count_sell, "neutral": count_neutral},
    }


# Poids partagés : tendance (H4+H1+D1) et exécution (M5+M15+M1) à parts égales
_IA_STATUS_TF_WEIGHTS: Dict[str, float] = {
    "H4":  0.20,   # Tendance principale
    "H1":  0.18,   # Contexte moyen terme
    "D1":  0.12,   # Biais macro
    "M5":  0.20,   # Anti-conflit + trigger
    "M15": 0.18,   # Court terme
    "M1":  0.08,   # Micro (poids réduit — bruit élevé)
    "M30": 0.04,   # Support
}


def compute_ia_status_v2(request: "DecisionRequest") -> Dict[str, Any]:
    """
    IA Status v2 : direction multi-TF, logique majorité pondérée.

    HOLD uniquement si marché indécis (gap < 0.15) OU M5 s'oppose à la majorité.
    M5 neutre sur tendance H4 claire = pause normale → BUY/SELL confiance moyenne.
    """
    symbol = str(request.symbol or "")

    tf_dirs: Dict[str, int] = {
        "D1":  _mtf_dir_from_mt5(symbol, "D1"),
        "H4":  _mtf_dir_from_mt5(symbol, "H4"),
        "H1":  _ema_dir(request.ema_fast_h1, request.ema_slow_h1),
        "M30": _mtf_dir_from_mt5(symbol, "M30"),
        "M15": _mtf_dir_from_mt5(symbol, "M15"),
        "M5":  _ema_dir(request.ema_fast_m5, request.ema_slow_m5),
        "M1":  _ema_dir(request.ema_fast_m1, request.ema_slow_m1),
    }

    result = _ia_status_decide(tf_dirs, _IA_STATUS_TF_WEIGHTS)
    result["timeframe_dirs"] = tf_dirs
    result["weights"] = _IA_STATUS_TF_WEIGHTS
    return result


def compute_mtf_funnel_decision(request: "DecisionRequest") -> Dict[str, Any]:
    """
    Entonnoir MTF:
    - Direction: W1/D1/H4
    - Zones: H1/M30
    - Trigger: M15
    - Exécution: M5/M1
    Returns final action/confidence + stage diagnostics.
    """
    symbol = str(request.symbol or "")
    tf_dirs: Dict[str, int] = {
        "W1": _mtf_dir_from_mt5(symbol, "W1"),
        "D1": _mtf_dir_from_mt5(symbol, "D1"),
        "H4": _mtf_dir_from_mt5(symbol, "H4"),
        "H1": _ema_dir(request.ema_fast_h1, request.ema_slow_h1),
        "M30": _mtf_dir_from_mt5(symbol, "M30"),
        "M15": _mtf_dir_from_mt5(symbol, "M15"),
        "M5": _ema_dir(request.ema_fast_m5, request.ema_slow_m5),
        "M1": _ema_dir(request.ema_fast_m1, request.ema_slow_m1),
    }

    def stage_dir(items: Dict[str, float], threshold: float = 0.10) -> int:
        score = 0.0
        total = 0.0
        for tf, w in items.items():
            d = tf_dirs.get(tf, 0)
            if d == 0:
                continue
            score += d * w
            total += abs(w)
        if total <= 0.0:
            return 0
        norm = score / total
        if norm >= threshold:
            return 1
        if norm <= -threshold:
            return -1
        return 0

    macro = stage_dir({"W1": 0.35, "D1": 0.35, "H4": 0.30})
    zones = stage_dir({"H1": 0.55, "M30": 0.45})
    trigger = stage_dir({"M15": 1.0})
    entry = stage_dir({"M5": 0.6, "M1": 0.4})

    # Final decision logic (conservative if stages conflict)
    final_dir = 0
    conflict = False
    if macro == 0:
        final_dir = 0
    else:
        final_dir = macro
        for s in (zones, trigger, entry):
            if s != 0 and s != macro:
                conflict = True
                final_dir = 0
                break

    aligned_count = sum(
        1 for s in (macro, zones, trigger, entry) if (s != 0 and s == (macro if macro != 0 else s))
    )
    confidence = 0.50 + min(0.40, aligned_count * 0.10)
    if conflict:
        confidence = max(0.45, confidence - 0.15)
    confidence = max(0.0, min(0.99, confidence))

    action = "hold"
    if final_dir > 0:
        action = "buy"
    elif final_dir < 0:
        action = "sell"

    return {
        "action": action,
        "confidence": confidence,
        "macro": macro,
        "zones": zones,
        "trigger": trigger,
        "entry": entry,
        "timeframe_dirs": tf_dirs,
        "conflict": conflict,
    }

# ========== DÉTECTION FIGURES CHARTISTES (SERVEUR IA) ==========
def _normalize_pattern_direction(direction: Optional[str]) -> str:
    d = str(direction or "").strip().lower()
    if d in {"buy", "bull", "bullish", "up"}:
        return "buy"
    if d in {"sell", "bear", "bearish", "down"}:
        return "sell"
    return "neutral"


def _extract_local_extrema(series: np.ndarray, order: int = 2) -> Tuple[List[int], List[int]]:
    mins: List[int] = []
    maxs: List[int] = []
    n = int(len(series))
    if n < (order * 2 + 3):
        return mins, maxs
    for i in range(order, n - order):
        w = series[i - order:i + order + 1]
        c = series[i]
        if np.all(c <= w):
            mins.append(i)
        if np.all(c >= w):
            maxs.append(i)
    return mins, maxs


def detect_chart_pattern_from_mt5(symbol: str, lookback: int = 180) -> Dict[str, Any]:
    neutral = {
        "name": "NONE",
        "direction": "neutral",
        "score": 0.0,
        "zone_low": None,
        "zone_high": None,
        "source": "server_mt5",
        "details": "",
    }
    try:
        if not symbol or not MT5_AVAILABLE or not mt5_initialized:
            return neutral
        rates = mt5.copy_rates_from_pos(symbol, mt5.TIMEFRAME_M5, 0, max(80, int(lookback)))
        if rates is None or len(rates) < 80:
            return neutral
        df = pd.DataFrame(rates)
        if not {"high", "low", "close"}.issubset(df.columns):
            return neutral

        highs = df["high"].astype(float).to_numpy()
        lows = df["low"].astype(float).to_numpy()
        closes = df["close"].astype(float).to_numpy()
        n = len(closes)
        if n < 80:
            return neutral

        tr = np.maximum(highs[1:] - lows[1:], np.abs(closes[1:] - closes[:-1]))
        atr = float(np.mean(tr[-40:])) if len(tr) >= 40 else float(np.mean(tr)) if len(tr) > 0 else 0.0
        atr = max(atr, 1e-9)

        minima, maxima = _extract_local_extrema(lows, order=2)
        max_close, _ = _extract_local_extrema(closes, order=2)
        maxima = sorted(set(maxima + max_close))
        candidates: List[Dict[str, Any]] = []

        if len(minima) >= 2:
            i1, i2 = minima[-2], minima[-1]
            if i2 - i1 >= 5:
                seg_hi = highs[i1:i2 + 1]
                if len(seg_hi) > 0:
                    peak_idx = int(i1 + int(np.argmax(seg_hi)))
                    l1 = float(lows[i1]); l2 = float(lows[i2]); pk = float(highs[peak_idx])
                    tol = max(atr * 0.8, abs(pk) * 0.00035)
                    lows_similarity = max(0.0, 1.0 - abs(l1 - l2) / max(tol, 1e-9))
                    rebound = max(0.0, min(1.2, (pk - max(l1, l2)) / atr))
                    breakout = 1.0 if closes[-1] > pk else max(0.0, min(1.0, (closes[-1] - max(l1, l2)) / max(pk - max(l1, l2), atr)))
                    score = 0.34 * lows_similarity + 0.33 * min(1.0, rebound) + 0.33 * breakout
                    if score >= 0.56:
                        candidates.append({
                            "name": "DOUBLE_BOTTOM_W",
                            "direction": "buy",
                            "score": float(min(0.95, score)),
                            "zone_low": float(min(l1, l2)),
                            "zone_high": float(pk),
                            "source": "server_mt5",
                            "details": f"W i1={i1} i2={i2} breakout={breakout:.2f}",
                        })

        if len(minima) >= 3:
            a, b, c = minima[-3], minima[-2], minima[-1]
            if (b - a >= 4) and (c - b >= 4):
                la = float(lows[a]); lb = float(lows[b]); lc = float(lows[c])
                if lb < la and lb < lc:
                    left_peak = float(np.max(highs[a:b + 1])) if b > a else float(highs[b])
                    right_peak = float(np.max(highs[b:c + 1])) if c > b else float(highs[c])
                    neckline = (left_peak + right_peak) * 0.5
                    shoulder_tol = max(atr * 0.9, abs(neckline) * 0.0004)
                    shoulders_similarity = max(0.0, 1.0 - abs(la - lc) / max(shoulder_tol, 1e-9))
                    head_depth = max(0.0, min(1.2, (min(la, lc) - lb) / atr))
                    breakout = 1.0 if closes[-1] > neckline else max(0.0, min(1.0, (closes[-1] - lb) / max(neckline - lb, atr)))
                    score = 0.38 * shoulders_similarity + 0.32 * min(1.0, head_depth) + 0.30 * breakout
                    if score >= 0.58:
                        candidates.append({
                            "name": "INVERSE_HEAD_SHOULDERS",
                            "direction": "buy",
                            "score": float(min(0.97, score)),
                            "zone_low": float(min(la, lb, lc)),
                            "zone_high": float(neckline),
                            "source": "server_mt5",
                            "details": f"IHS a={a} b={b} c={c} breakout={breakout:.2f}",
                        })

        if len(maxima) >= 2:
            j1, j2 = maxima[-2], maxima[-1]
            if j2 - j1 >= 5:
                seg_lo = lows[j1:j2 + 1]
                if len(seg_lo) > 0:
                    trough_idx = int(j1 + int(np.argmin(seg_lo)))
                    h1 = float(highs[j1]); h2 = float(highs[j2]); trw = float(lows[trough_idx])
                    tol = max(atr * 0.8, abs(trw) * 0.00035)
                    highs_similarity = max(0.0, 1.0 - abs(h1 - h2) / max(tol, 1e-9))
                    retrace = max(0.0, min(1.2, (min(h1, h2) - trw) / atr))
                    breakout = 1.0 if closes[-1] < trw else max(0.0, min(1.0, (max(h1, h2) - closes[-1]) / max(max(h1, h2) - trw, atr)))
                    score = 0.34 * highs_similarity + 0.33 * min(1.0, retrace) + 0.33 * breakout
                    if score >= 0.56:
                        candidates.append({
                            "name": "DOUBLE_TOP_M",
                            "direction": "sell",
                            "score": float(min(0.95, score)),
                            "zone_low": float(trw),
                            "zone_high": float(max(h1, h2)),
                            "source": "server_mt5",
                            "details": f"M j1={j1} j2={j2} breakout={breakout:.2f}",
                        })

        if len(maxima) >= 3:
            x, y, z = maxima[-3], maxima[-2], maxima[-1]
            if (y - x >= 4) and (z - y >= 4):
                hx = float(highs[x]); hy = float(highs[y]); hz = float(highs[z])
                if hy > hx and hy > hz:
                    left_tr = float(np.min(lows[x:y + 1])) if y > x else float(lows[y])
                    right_tr = float(np.min(lows[y:z + 1])) if z > y else float(lows[z])
                    neckline = (left_tr + right_tr) * 0.5
                    shoulder_tol = max(atr * 0.9, abs(neckline) * 0.0004)
                    shoulders_similarity = max(0.0, 1.0 - abs(hx - hz) / max(shoulder_tol, 1e-9))
                    head_height = max(0.0, min(1.2, (hy - max(hx, hz)) / atr))
                    breakout = 1.0 if closes[-1] < neckline else max(0.0, min(1.0, (hy - closes[-1]) / max(hy - neckline, atr)))
                    score = 0.38 * shoulders_similarity + 0.32 * min(1.0, head_height) + 0.30 * breakout
                    if score >= 0.58:
                        candidates.append({
                            "name": "HEAD_SHOULDERS",
                            "direction": "sell",
                            "score": float(min(0.97, score)),
                            "zone_low": float(neckline),
                            "zone_high": float(max(hx, hy, hz)),
                            "source": "server_mt5",
                            "details": f"HS x={x} y={y} z={z} breakout={breakout:.2f}",
                        })

        if not candidates:
            return neutral
        return max(candidates, key=lambda c: float(c.get("score", 0.0) or 0.0))
    except Exception as e:
        logger.debug(f"detect_chart_pattern_from_mt5: {e}")
        return neutral


def resolve_chart_pattern_signal(request: "DecisionRequest") -> Dict[str, Any]:
    neutral = {
        "name": "NONE",
        "direction": "neutral",
        "score": 0.0,
        "zone_low": None,
        "zone_high": None,
        "source": "none",
        "details": "",
    }
    candidates: List[Dict[str, Any]] = []

    try:
        req_name = str(request.chart_pattern_name or "").strip()
        req_dir = _normalize_pattern_direction(request.chart_pattern_direction)
        req_score_raw = float(request.chart_pattern_score or 0.0)
        req_score = req_score_raw / 100.0 if req_score_raw > 1.0 else req_score_raw
        if req_name and req_dir in {"buy", "sell"} and req_score > 0.0:
            candidates.append({
                "name": req_name.upper(),
                "direction": req_dir,
                "score": float(max(0.35, min(0.98, req_score))),
                "zone_low": request.chart_pattern_zone_low,
                "zone_high": request.chart_pattern_zone_high,
                "source": "mt5_client",
                "details": "provided_by_client",
            })
    except Exception:
        pass

    mt5_sig = detect_chart_pattern_from_mt5(str(request.symbol or ""))
    if mt5_sig.get("direction") in {"buy", "sell"} and float(mt5_sig.get("score", 0.0) or 0.0) > 0.0:
        candidates.append(mt5_sig)

    if not candidates:
        return neutral
    best = max(candidates, key=lambda c: float(c.get("score", 0.0) or 0.0))
    best["all_candidates"] = candidates
    return best


# ========== FONCTION SIMPLIFIÉE POUR ROBOCOP v2 ==========
# Modifier la fonction decision_simplified pour utiliser le ML
async def decision_simplified(request: DecisionRequest):
    """
    Fonction de décision simplifiée avec amélioration ML
    """
    global decision_count
    decision_count += 1
    
    cached_pre = get_simplified_tf_cached_decision(request)
    if cached_pre is not None:
        logger.debug(f"⚡ CACHE decision_simplified HIT [{decision_simplified_cache_key(request)}]")
        return cached_pre
    
    logger.info(f"🎯 MODE SIMPLIFIÉ + ML - Requête décision pour {request.symbol}")
    try:
        update_spike_state_from_request(request)
    except Exception as e:
        logger.debug(f"⚠️ update_spike_state_from_request (simplifié) erreur: {e}")
    logger.info(f"   Bid: {request.bid}, Ask: {request.ask}, RSI: {request.rsi}")
    
    # Analyse technique de base
    action = "hold"
    confidence = 0.5
    reason = "Analyse technique multi-timeframe"
    
    # Scores pondérés par timeframe
    buy_score = 0.0
    sell_score = 0.0
    
    # 1. Analyse RSI (poids: 15%)
    if request.rsi:
        if request.rsi < 30:
            buy_score += 0.15
            reason += f"RSI surventé ({request.rsi:.1f}). "
        elif request.rsi > 70:
            sell_score += 0.15
            reason += f"RSI surachat ({request.rsi:.1f}). "
        elif 30 <= request.rsi <= 40:
            buy_score += 0.08
            reason += f"RSI zone survente ({request.rsi:.1f}). "
        elif 60 <= request.rsi <= 70:
            sell_score += 0.08
            reason += f"RSI zone surachat ({request.rsi:.1f}). "
    
    # 2. Analyse EMA M1 (poids: 20%)
    if request.ema_fast_m1 and request.ema_slow_m1:
        ema_diff_m1 = request.ema_fast_m1 - request.ema_slow_m1
        ema_strength_m1 = abs(ema_diff_m1) / request.ema_slow_m1 if request.ema_slow_m1 > 0 else 0
        
        if ema_diff_m1 > 0:
            buy_score += 0.20 * min(1.0, ema_strength_m1 * 100)
            reason += f"EMA M1 haussière (+{ema_strength_m1*100:.1f}%). "
        else:
            sell_score += 0.20 * min(1.0, ema_strength_m1 * 100)
            reason += f"EMA M1 baissière ({ema_strength_m1*100:.1f}%). "
    
    # 3. Analyse EMA H1 (poids: 35%)
    if request.ema_fast_h1 and request.ema_slow_h1:
        ema_diff_h1 = request.ema_fast_h1 - request.ema_slow_h1
        ema_strength_h1 = abs(ema_diff_h1) / request.ema_slow_h1 if request.ema_slow_h1 > 0 else 0
        
        if ema_diff_h1 > 0:
            buy_score += 0.35 * min(1.0, ema_strength_h1 * 50)
            reason += f"EMA H1 haussière (+{ema_strength_h1*50:.1f}%). "
        else:
            sell_score += 0.35 * min(1.0, ema_strength_h1 * 50)
            reason += f"EMA H1 baissière ({ema_strength_h1*50:.1f}%). "
    
    # 4. Analyse EMA M5 (poids: 25%)
    if request.ema_fast_m5 and request.ema_slow_m5:
        ema_diff_m5 = request.ema_fast_m5 - request.ema_slow_m5
        ema_strength_m5 = abs(ema_diff_m5) / request.ema_slow_m5 if request.ema_slow_m5 > 0 else 0
        
        if ema_diff_m5 > 0:
            buy_score += 0.25 * min(1.0, ema_strength_m5 * 75)
            reason += f"EMA M5 haussière (+{ema_strength_m5*75:.1f}%). "
        else:
            sell_score += 0.25 * min(1.0, ema_strength_m5 * 75)
            reason += f"EMA M5 baissière ({ema_strength_m5*75:.1f}%). "

    # 4c. Figures chartistes (W/M/ETE/ETE inversée) modélisées côté serveur IA
    chart_pattern_signal = resolve_chart_pattern_signal(request)
    cp_dir = str(chart_pattern_signal.get("direction", "neutral"))
    cp_score = float(chart_pattern_signal.get("score", 0.0) or 0.0)
    if cp_dir in {"buy", "sell"} and cp_score > 0.0:
        cp_bonus = min(0.24, max(0.06, cp_score * 0.22))
        cp_name = str(chart_pattern_signal.get("name", "PATTERN"))
        if cp_dir == "buy":
            buy_score += cp_bonus
            sell_score = max(0.0, sell_score - cp_bonus * 0.30)
            reason += f"Pattern {cp_name} bullish (+{cp_bonus:.2f}). "
        else:
            sell_score += cp_bonus
            buy_score = max(0.0, buy_score - cp_bonus * 0.30)
            reason += f"Pattern {cp_name} bearish (+{cp_bonus:.2f}). "
    
    # 4b. Boom : bonus si M1+M5 haussiers (contrepoids au H1 baissier — stair M1 / scalp)
    try:
        if is_boom_crash_symbol(str(request.symbol)) and "boom" in str(request.symbol).lower():
            e1f = float(request.ema_fast_m1 or 0.0)
            e1s = float(request.ema_slow_m1 or 0.0)
            e5f = float(request.ema_fast_m5 or 0.0)
            e5s = float(request.ema_slow_m5 or 0.0)
            if e1f > e1s and e5f > e5s and e1s > 0.0 and e5s > 0.0:
                buy_score += 0.18
                reason += "[Boom: M1+M5 haussiers — bonus buy_score vs H1] "
    except Exception:
        pass

    # 4d. Rapport manuel CLI TradingAgents → pondération buy/sell (fusion avec analyse technique)
    # Si AI_TRADINGAGENTS_OVERRIDE=true : TradingAgents décide seul (bypass technique)
    _ta_override_enabled = _env_bool("AI_TRADINGAGENTS_OVERRIDE", default=False)
    _ta_manual_override: Optional[Dict] = None
    try:
        manual = await _peek_manual_tradingagents_report(str(request.symbol))
        if manual:
            rec = str(manual.get("recommendation") or "HOLD").strip().upper()
            mc = float(manual.get("confidence") or 0.0)
            if mc > 1.0:
                mc = min(1.0, mc / 100.0)
            if _ta_override_enabled and rec in ("BUY", "SELL") and mc >= 0.45:
                # Override direct: TradingAgents décide seul
                _ta_manual_override = {"action": rec.lower(), "confidence": mc, "rec": rec, "mc": mc}
                reason += f"[CLI TradingAgents OVERRIDE: {rec} {int(mc * 100)}%] "
            else:
                w = float(os.getenv("AI_TRADINGAGENTS_CLI_WEIGHT", "0.28"))
                if rec == "BUY" and mc >= 0.45:
                    buy_score += w * mc
                    reason += f"[CLI TradingAgents: BUY {int(mc * 100)}%] "
                elif rec == "SELL" and mc >= 0.45:
                    sell_score += w * mc
                    reason += f"[CLI TradingAgents: SELL {int(mc * 100)}%] "
                elif rec in ("HOLD", "NEUTRAL", "WAIT"):
                    reason += "[CLI TradingAgents: HOLD] "
    except Exception:
        pass

    # 5. Décision technique de base
    # Sur Boom/Crash, l'EA ne trade qu'un seul sens. Si on élit "buy" sur Crash (ex. H1 haussier qui pèse 35 %),
    # enforce_ea_boom_crash_direction ramène tout en HOLD : l'utilisateur voit des spikes baissiers mais IA=HOLD.
    sym_l = str(request.symbol or "").lower()
    is_crash_sc = is_boom_crash_symbol(str(request.symbol)) and "crash" in sym_l
    is_boom_sc = is_boom_crash_symbol(str(request.symbol)) and "boom" in sym_l

    if is_crash_sc:
        if sell_score >= buy_score:
            base_action = "sell"
            base_confidence = 0.5 + (sell_score - buy_score) / 2
            reason += "[Crash: score SELL≥BUY] "
        else:
            m1b = (
                request.ema_fast_m1 is not None
                and request.ema_slow_m1 is not None
                and float(request.ema_fast_m1) < float(request.ema_slow_m1)
            )
            m5b = (
                request.ema_fast_m5 is not None
                and request.ema_slow_m5 is not None
                and float(request.ema_fast_m5) < float(request.ema_slow_m5)
            )
            if m1b or m5b:
                base_action = "sell"
                base_confidence = max(0.58, 0.52 + sell_score * 0.45)
                reason += "[Crash: H1/pondération haussière mais M1/M5 baissiers (spikes) → SELL] "
            else:
                base_action = "hold"
                base_confidence = min(0.62, 0.48 + abs(buy_score - sell_score) * 0.15)
                reason += "[Crash: pas de base BUY (interdit EA) — HOLD si pas de M1/M5 baissiers] "
    elif is_boom_sc:
        if buy_score >= sell_score:
            base_action = "buy"
            base_confidence = 0.5 + (buy_score - sell_score) / 2
            reason += "[Boom: score BUY≥SELL] "
        else:
            m1u = (
                request.ema_fast_m1 is not None
                and request.ema_slow_m1 is not None
                and float(request.ema_fast_m1) > float(request.ema_slow_m1)
            )
            m5u = (
                request.ema_fast_m5 is not None
                and request.ema_slow_m5 is not None
                and float(request.ema_fast_m5) > float(request.ema_slow_m5)
            )
            if m1u or m5u:
                base_action = "buy"
                base_confidence = max(0.58, 0.52 + buy_score * 0.45)
                reason += "[Boom: H1/pondération baissière mais M1/M5 haussiers → BUY] "
            else:
                base_action = "hold"
                base_confidence = min(0.62, 0.48 + abs(buy_score - sell_score) * 0.15)
                reason += "[Boom: pas de base SELL (interdit EA) — HOLD si pas de M1/M5 haussiers] "
    elif buy_score > sell_score:
        base_action = "buy"
        base_confidence = 0.5 + (buy_score - sell_score) / 2
    elif sell_score > buy_score:
        base_action = "sell"
        base_confidence = 0.5 + (sell_score - buy_score) / 2
    else:
        base_action = "hold"
        base_confidence = 0.5

    # Override TradingAgents: bypasse la fusion technique si AI_TRADINGAGENTS_OVERRIDE=true
    if _ta_manual_override:
        base_action = _ta_manual_override["action"]
        base_confidence = max(0.55, _ta_manual_override["confidence"])
        logger.info("🤖 TradingAgents OVERRIDE actif: %s %.0f%%", base_action.upper(), base_confidence * 100)

    # 6. AMÉLIORATION AVEC ML
    market_data = {
        "symbol": request.symbol,
        "bid": request.bid,
        "ask": request.ask,
        "rsi": request.rsi,
        "ema_fast_m1": request.ema_fast_m1,
        "ema_slow_m1": request.ema_slow_m1,
        "ema_fast_h1": request.ema_fast_h1,
        "ema_slow_h1": request.ema_slow_h1,
        "ema_fast_m5": request.ema_fast_m5,
        "ema_slow_m5": request.ema_slow_m5,
        "atr": request.atr,
        "timestamp": request.timestamp,
        "chart_pattern_name": chart_pattern_signal.get("name"),
        "chart_pattern_direction": chart_pattern_signal.get("direction"),
        "chart_pattern_score": chart_pattern_signal.get("score"),
    }
    
    ml_result = enhance_decision_with_ml(request.symbol, base_action, base_confidence, market_data)
    
    # Utiliser la décision améliorée par ML
    action = ml_result["enhanced_decision"]
    confidence = ml_result["enhanced_confidence"]
    
    # Ajouter la raison ML à la raison technique
    if ml_result["ml_applied"]:
        reason += f"[ML: {ml_result['ml_reason']}] "
        logger.info(f"🧠 ML Enhancement: {base_action} → {action} ({base_confidence:.2f} → {confidence:.2f})")
    
    action, confidence, reason = enforce_ea_boom_crash_direction(
        request.symbol, action, confidence, reason
    )
    
    # 7. Règles agressives spécifiques Boom/Crash (plus de BUY/SELL, moins de HOLD)
    # Ne pas dépendre de IMPROVEMENTS_AVAILABLE : alignement critique pour MT5 / stair M1.
    try:
        if is_boom_crash_symbol(str(request.symbol)):
            symbol_lower = str(request.symbol).lower()
            is_boom = "boom" in symbol_lower
            is_crash = "crash" in symbol_lower
            
            ema_fast_m1 = request.ema_fast_m1 or 0.0
            ema_slow_m1 = request.ema_slow_m1 or 0.0
            ema_fast_m5 = request.ema_fast_m5 or 0.0
            ema_slow_m5 = request.ema_slow_m5 or 0.0
            ema_fast_h1 = request.ema_fast_h1 or 0.0
            ema_slow_h1 = request.ema_slow_h1 or 0.0
            
            ema_up = (
                (ema_fast_m1 > ema_slow_m1) or
                (ema_fast_m5 > ema_slow_m5) or
                (ema_fast_h1 > ema_slow_h1)
            )
            ema_down = (
                (ema_fast_m1 < ema_slow_m1) or
                (ema_fast_m5 < ema_slow_m5) or
                (ema_fast_h1 < ema_slow_h1)
            )
            
            # Si IA est en HOLD mais la tendance est claire, forcer une décision
            if action == "hold":
                if is_boom and ema_up:
                    action = "buy"
                    confidence = max(confidence, 0.6)
                    reason += "[Boom agressif: tendance haussière → BUY] "
                elif is_crash and ema_down:
                    action = "sell"
                    confidence = max(confidence, 0.6)
                    reason += "[Crash agressif: tendance baissière → SELL] "
            
            # Si déjà BUY/SELL aligné avec la tendance, renforcer légèrement la confiance
            elif is_boom and action == "buy" and ema_up:
                confidence = min(0.95, max(confidence, 0.7))
                reason += "[Boom agressif: BUY confirmé par tendance] "
            elif is_crash and action == "sell" and ema_down:
                confidence = min(0.95, max(confidence, 0.7))
                reason += "[Crash agressif: SELL confirmé par tendance] "
    except Exception as e:
        logger.debug(f"Règles agressives Boom/Crash ignorées: {e}")
    
    # 7b. Historique stair (Supabase) : ajuste la confiance si win_rate significatif pour symbole+direction
    try:
        if request.stair_detected:
            action, confidence, reason = await apply_stair_history_to_decision(
                str(request.symbol or ""),
                action,
                confidence,
                reason,
                bool(request.stair_detected),
                request.stair_direction,
                request.stair_pattern_kinds,
            )
    except Exception as e:
        logger.debug("apply_stair_history_to_decision: %s", e)
    
    # 7c. Validation finale RSI / MACD / Ichimoku (confluence)
    # Skippé si TradingAgents override actif (TA décide seul)
    confluence_detail: Dict[str, Any] = {}
    if _ta_manual_override is None and INDICATOR_CONFLUENCE_AVAILABLE and apply_core_indicator_confluence and _env_bool(
        "ENABLE_CORE_INDICATOR_CONFLUENCE", True
    ):
        try:
            min_v = int(os.getenv("CORE_INDICATOR_MIN_VOTES", "2"))
            action, confidence, reason, confluence_detail = apply_core_indicator_confluence(
                request, action, confidence, reason, min_votes=max(1, min_v)
            )
            if confluence_detail and not confluence_detail.get("skipped"):
                logger.info(
                    "📊 Confluence RSI/MACD/Ichi | %s | votes=%s/%s | %s",
                    request.symbol,
                    confluence_detail.get("votes_for"),
                    confluence_detail.get("votes_against"),
                    confluence_detail.get("core_labels"),
                )
        except Exception as e:
            logger.debug("confluence: %s", e)
    
    # 8. Ajustements finaux (laisser une confiance dynamique sur HOLD, éviter un plancher fixe à 30%)
    if action == "hold":
        # Garder la confiance calculée (technique + ML), mais éviter 0 absolu
        confidence = max(0.1, confidence)

    # 8b. Entonnoir MTF (W1/D1/H4 -> H1/M30 -> M15 -> M5/M1) pour décision finale.
    # Skippé si TradingAgents override actif
    if _ta_manual_override is not None:
        reason += f" [Funnel MTF ignoré: TradingAgents OVERRIDE {action.upper()}]"
    funnel = compute_mtf_funnel_decision(request)
    funnel_action = funnel.get("action", "hold") if _ta_manual_override is None else action
    funnel_conf = float(funnel.get("confidence", 0.5))
    if funnel_action == action:
        confidence = max(confidence, funnel_conf)
        reason += f" [Funnel MTF aligné: {funnel_action.upper()}]"
    elif action == "hold" and funnel_action in ("buy", "sell"):
        action = funnel_action
        confidence = max(confidence, funnel_conf * 0.95)
        reason += f" [Funnel MTF a déclenché {funnel_action.upper()}]"
    elif action in ("buy", "sell") and funnel_action == "hold":
        sym_l_fc = str(request.symbol or "").lower()
        skip_funnel_hold = False
        if is_boom_crash_symbol(str(request.symbol)):
            if "boom" in sym_l_fc and action == "buy":
                m1u = (
                    request.ema_fast_m1 is not None
                    and request.ema_slow_m1 is not None
                    and float(request.ema_fast_m1) > float(request.ema_slow_m1)
                )
                m5u = (
                    request.ema_fast_m5 is not None
                    and request.ema_slow_m5 is not None
                    and float(request.ema_fast_m5) > float(request.ema_slow_m5)
                )
                if m1u or m5u:
                    skip_funnel_hold = True
                    reason += " [Funnel MTF ignoré: Boom M1/M5 haussiers]"
            elif "crash" in sym_l_fc and action == "sell":
                m1d = (
                    request.ema_fast_m1 is not None
                    and request.ema_slow_m1 is not None
                    and float(request.ema_fast_m1) < float(request.ema_slow_m1)
                )
                m5d = (
                    request.ema_fast_m5 is not None
                    and request.ema_slow_m5 is not None
                    and float(request.ema_fast_m5) < float(request.ema_slow_m5)
                )
                if m1d or m5d:
                    skip_funnel_hold = True
                    reason += " [Funnel MTF ignoré: Crash M1/M5 baissiers]"
        if not skip_funnel_hold:
            action = "hold"
            confidence = max(0.45, min(confidence, funnel_conf))
            reason += " [Funnel MTF: conflit inter-TF -> HOLD]"
    elif action != funnel_action and funnel_action in ("buy", "sell"):
        action = "hold"
        confidence = max(0.45, min(confidence, funnel_conf))
        reason += " [Funnel MTF: désaccord final -> HOLD]"
    
    # 8c. Fusion décision technique + Qwen local (Ollama).
    # Objectif: associer la décision du script (entry points / niveaux) avec l'analyse Qwen.
    qwen_meta: Dict[str, Any] = {}
    stop_loss = None
    take_profit = None
    qwen_sched_note = "QWEN=OFF"
    # Désactivé par défaut : Qwen/Ollama ne doit pas piloter /decision (analyses séparées /analyze/ollama si besoin).
    if _env_bool("ENABLE_QWEN_DECISION_BLEND", False):
        try:
            # Charger la config runtime (permet override via .env sans redéployer)
            global QWEN_ROTATION_ENABLED, QWEN_ROTATION_STEP_SECONDS, QWEN_SYMBOL_REVISIT_SECONDS
            QWEN_ROTATION_ENABLED = _env_bool("QWEN_ROTATION_ENABLED", True)
            try:
                QWEN_ROTATION_STEP_SECONDS = max(60, int(os.getenv("QWEN_ROTATION_STEP_SECONDS", "300")))
            except Exception:
                QWEN_ROTATION_STEP_SECONDS = 300
            try:
                QWEN_SYMBOL_REVISIT_SECONDS = max(120, int(os.getenv("QWEN_SYMBOL_REVISIT_SECONDS", "900")))
            except Exception:
                QWEN_SYMBOL_REVISIT_SECONDS = 900

            # Scheduler Qwen: un symbole par slot, revisit mini par symbole
            sym_key = str(request.symbol or "").strip().upper()
            now_ts = time.time()
            can_run_qwen = True
            sched_reason = "ok"
            slot_symbol = sym_key
            wait_seconds = 0

            if QWEN_ROTATION_ENABLED:
                if not sym_key or sym_key == "UNKNOWN":
                    can_run_qwen = False
                    sched_reason = "unknown_symbol"
                else:
                    if sym_key not in qwen_symbol_ring:
                        qwen_symbol_ring.append(sym_key)
                    ring_len = len(qwen_symbol_ring)
                    if ring_len <= 0:
                        can_run_qwen = False
                        sched_reason = "ring_empty"
                    else:
                        slot_idx = int(now_ts // QWEN_ROTATION_STEP_SECONDS) % ring_len
                        slot_symbol = qwen_symbol_ring[slot_idx]
                        if sym_key != slot_symbol:
                            can_run_qwen = False
                            sched_reason = "slot_mismatch"
                            wait_seconds = int(QWEN_ROTATION_STEP_SECONDS - (now_ts % QWEN_ROTATION_STEP_SECONDS))
                        else:
                            last_run = qwen_symbol_last_run.get(sym_key, 0.0)
                            age = now_ts - last_run if last_run > 0 else 1e9
                            if age < QWEN_SYMBOL_REVISIT_SECONDS:
                                can_run_qwen = False
                                sched_reason = "revisit_window"
                                wait_seconds = int(QWEN_SYMBOL_REVISIT_SECONDS - age)

            # Exception opportunité forte: autoriser Qwen même hors slot.
            # Cas visé: marché en mouvement, prix proche des entries script + momentum exploitable.
            def _near_level(price: Optional[float], lvl: Optional[float], atr_v: Optional[float]) -> bool:
                try:
                    if price is None or lvl is None or atr_v is None:
                        return False
                    p = float(price); l = float(lvl); a = float(atr_v)
                    if p <= 0 or l <= 0 or a <= 0:
                        return False
                    return abs(p - l) <= a * 0.45
                except Exception:
                    return False

            is_strong_opportunity = False
            try:
                bid_v = float(request.bid or 0.0)
                atr_v = float(request.atr or 0.0)
                rsi_v = float(request.rsi or 50.0)
                near_buy = (
                    _near_level(bid_v, request.m5_buy_entry_point, atr_v) or
                    _near_level(bid_v, request.m15_buy_entry_point, atr_v)
                )
                near_sell = (
                    _near_level(bid_v, request.m5_sell_entry_point, atr_v) or
                    _near_level(bid_v, request.m15_sell_entry_point, atr_v)
                )
                momentum_extreme = (rsi_v <= 42.0 or rsi_v >= 58.0)
                is_strong_opportunity = (momentum_extreme and (near_buy or near_sell))
            except Exception:
                is_strong_opportunity = False

            if (not can_run_qwen) and is_strong_opportunity:
                can_run_qwen = True
                sched_reason = "opportunity_override"
                logger.info("🧠 Qwen scheduler override %s (opportunité forte)", sym_key or "UNKNOWN")

            if not can_run_qwen:
                qwen_sched_note = "QWEN=SKIP|" + sched_reason + "|w=" + str(max(0, wait_seconds)) + "s"
                qwen_meta = {
                    "enabled": True,
                    "status": "scheduled_skip",
                    "reason": sched_reason,
                    "symbol": sym_key,
                    "slot_symbol": slot_symbol,
                    "wait_seconds": max(0, wait_seconds),
                    "ring_size": len(qwen_symbol_ring),
                    "rotation_step_seconds": QWEN_ROTATION_STEP_SECONDS,
                    "revisit_seconds": QWEN_SYMBOL_REVISIT_SECONDS,
                }
                logger.info(
                    "🧠 Qwen scheduler skip %s reason=%s slot=%s wait=%ss ring=%d",
                    sym_key or "UNKNOWN", sched_reason, slot_symbol, max(0, wait_seconds), len(qwen_symbol_ring)
                )
            else:
                qwen_sched_note = "QWEN=RUN|" + (slot_symbol if slot_symbol else sym_key)
                logger.info(
                    "🧠 Qwen scheduler run %s slot=%s ring=%d",
                    sym_key, slot_symbol, len(qwen_symbol_ring)
                )

            tf_label = str(getattr(request, "timeframe", None) or "M5")
            if can_run_qwen:
                oreq = OllamaAnalysisRequest(
                    symbol=str(request.symbol or "UNKNOWN"),
                    timeframe=tf_label,
                    bid=request.bid,
                    ask=request.ask,
                    rsi=request.rsi,
                    ema_fast_m1=request.ema_fast_m1,
                    ema_slow_m1=request.ema_slow_m1,
                    ema_fast_m5=request.ema_fast_m5,
                    ema_slow_m5=request.ema_slow_m5,
                    ema_fast_h1=request.ema_fast_h1,
                    ema_slow_h1=request.ema_slow_h1,
                    atr=request.atr,
                    m1_buy_entry=request.m1_buy_entry_point,
                    m1_sell_entry=request.m1_sell_entry_point,
                    m5_buy_entry=request.m5_buy_entry_point,
                    m5_sell_entry=request.m5_sell_entry_point,
                    m15_buy_entry=request.m15_buy_entry_point,
                    m15_sell_entry=request.m15_sell_entry_point,
                    h1_buy_entry=request.h1_buy_entry_point,
                    h1_sell_entry=request.h1_sell_entry_point,
                    macd_histogram=request.macd_histogram,
                    ichimoku_bias=request.ichimoku_bias,
                    timestamp=request.timestamp,
                    recent_candles=request.recent_candles,
                )
                q_model = os.getenv("OLLAMA_MODEL", "qwen3.5:4b")
                q_timeout = int(os.getenv("QWEN_DECISION_TIMEOUT_SECONDS", "8"))
                q_prompt = _build_ollama_prompt(oreq)
                q_raw = _call_ollama_local(q_prompt, model=q_model, timeout=q_timeout)
                if q_raw:
                    q_parsed = _parse_ollama_json(q_raw)
                    q_rec = str(q_parsed.get("recommendation", "HOLD") or "HOLD").strip().upper()
                    q_conf = float(q_parsed.get("confidence", 0.5) or 0.5)
                    if q_conf > 1.0:
                        q_conf = q_conf / 100.0
                    q_conf = max(0.0, min(1.0, q_conf))
                    q_reason = str(q_parsed.get("reasoning", "") or "").strip()
                    q_levels = q_parsed.get("key_levels", {}) if isinstance(q_parsed.get("key_levels", {}), dict) else {}

                    q_action = "hold"
                    if q_rec == "BUY":
                        q_action = "buy"
                    elif q_rec == "SELL":
                        q_action = "sell"
                    logger.info("🧠 Qwen blend %s: rec=%s conf=%.2f", request.symbol, q_rec, q_conf)

                    # Règles de fusion:
                    # - alignement => renfort confiance
                    # - désaccord BUY/SELL => HOLD de sécurité
                    if q_action == action and q_action in ("buy", "sell"):
                        confidence = min(0.98, max(confidence, q_conf))
                        reason += f" [Qwen aligné {q_action.upper()} {int(q_conf*100)}%]"
                    elif action == "hold" and q_action in ("buy", "sell") and q_conf >= 0.62:
                        action = q_action
                        confidence = max(confidence, q_conf * 0.95)
                        reason += f" [Qwen a déclenché {q_action.upper()}]"
                    elif action in ("buy", "sell") and q_action in ("buy", "sell") and q_action != action:
                        action = "hold"
                        confidence = max(0.45, min(confidence, q_conf))
                        reason += " [Conflit technique/Qwen -> HOLD]"

                    # Utiliser les niveaux Qwen si présents pour améliorer SL/TP
                    try:
                        q_sl = float(q_levels.get("stop_loss")) if q_levels.get("stop_loss") is not None else None
                    except Exception:
                        q_sl = None
                    try:
                        q_tp = float(q_levels.get("take_profit_1")) if q_levels.get("take_profit_1") is not None else None
                    except Exception:
                        q_tp = None

                    if action == "buy":
                        if q_sl is not None and q_sl > 0:
                            stop_loss = q_sl
                        if q_tp is not None and q_tp > 0:
                            take_profit = q_tp
                    elif action == "sell":
                        if q_sl is not None and q_sl > 0:
                            stop_loss = q_sl
                        if q_tp is not None and q_tp > 0:
                            take_profit = q_tp

                    qwen_symbol_last_run[sym_key] = now_ts
                    qwen_meta = {
                        "enabled": True,
                        "model": q_model,
                        "recommendation": q_rec,
                        "action": q_action,
                        "confidence": q_conf,
                        "reasoning": q_reason,
                        "key_levels": q_levels,
                        "scheduler": {
                            "slot_symbol": slot_symbol,
                            "ring_size": len(qwen_symbol_ring),
                            "rotation_step_seconds": QWEN_ROTATION_STEP_SECONDS,
                            "revisit_seconds": QWEN_SYMBOL_REVISIT_SECONDS,
                        },
                    }
                else:
                    qwen_sched_note = "QWEN=NORESP"
                    qwen_meta = {"enabled": True, "model": q_model, "status": "no_response"}
        except Exception as e:
            logger.warning("Qwen blend error: %s", e)
            qwen_sched_note = "QWEN=ERR"
            qwen_meta = {"enabled": True, "status": "error", "error": str(e)}
    else:
        qwen_meta = {"enabled": False}
    reason += " [" + qwen_sched_note + "]"

    # 9. Confiance pour MT5: envoyer décimale 0-1 (l'EA attend 0-1 et affiche *100)
    confidence_percentage = confidence
    
    # 10. Calcul SL/TP (si non déjà définis par la fusion Qwen)
    
    if action == "buy" and request.bid and stop_loss is None and take_profit is None:
        atr = request.atr if request.atr and request.atr > 0 else 0.0020
        stop_loss = request.bid - atr * 2
        take_profit = request.bid + atr * 3
    elif action == "sell" and request.ask and stop_loss is None and take_profit is None:
        atr = request.atr if request.atr and request.atr > 0 else 0.0020
        stop_loss = request.ask + atr * 2
        take_profit = request.ask - atr * 3

    # 10b. Stratégie Divergence (indices Deriv) — div F̄ + trend + ATR SL/TP
    divergence_meta: Dict[str, Any] = {}
    try:
        action, confidence, reason, stop_loss, take_profit, divergence_meta = (
            apply_divergence_strategy_to_decision(
                request, action, confidence, reason, stop_loss, take_profit
            )
        )
        action, confidence, reason = enforce_ea_boom_crash_direction(
            request.symbol, action, confidence, reason
        )
        if divergence_meta and action in ("buy", "sell"):
            reason += " [Div→MT5 market]"
    except Exception as div_err:
        logger.debug("divergence merge (simplified): %s", div_err)
    
    # 11. Préparer les prédictions (simuler une tendance basée sur RSI/EMA si pas de modèle ML complexe)
    predicted_prices = []
    if request.bid:
        p = request.bid
        # Tendance simplifiée pour le canal
        step = 0
        if action == "buy": step = 0.00001
        elif action == "sell": step = -0.00001
        
        for _ in range(500):
            p += step + (np.random.normal(0, 0.000005))
            predicted_prices.append(float(p))
            
    # 12. Déterminer alignement et cohérence
    alignment = "N/A"
    if request.ema_fast_m1 and request.ema_fast_m5 and request.ema_fast_h1:
        m1_up = request.ema_fast_m1 > request.ema_slow_m1
        m5_up = request.ema_fast_m5 > request.ema_slow_m5
        h1_up = request.ema_fast_h1 > request.ema_slow_h1
        if m1_up == m5_up == h1_up:
            alignment = "M1/M5/H1: ALIGNÉ (" + ("HAUSSIER" if m1_up else "BAISSIER") + ")"
        else:
            alignment = "M1/M5/H1: MIXTE"
            
    coherence = f"COHÉRENCE: {int(confidence * 100)}%"
    
    # 12b. TradingAgents (cache RT + rapport manuel) → prix d'entrée, type d'ordre, SL/TP pour MT5
    entry_price_out: Optional[float] = None
    execution_type_out: Optional[str] = None
    if _env_bool("AI_TRADINGAGENTS_EXEC_MERGE_ENABLED", True):
        try:
            ta_hints = await _collect_tradingagents_execution_hints(str(request.symbol))
            min_c = float(os.getenv("AI_TRADINGAGENTS_EXEC_MERGE_MIN_CONF", "0.55"))
            ta_rec = str(ta_hints.get("_recommendation") or ta_hints.get("recommendation") or "HOLD").strip().upper()
            ta_conf = float(ta_hints.get("_confidence") or ta_hints.get("confidence") or 0.0)
            side_match = (
                (action == "buy" and ta_rec == "BUY")
                or (action == "sell" and ta_rec == "SELL")
            )
            if ta_conf >= min_c and side_match and action in ("buy", "sell"):
                et = (ta_hints.get("execution_type") or "").strip().lower()
                if et in ("limit", "stop", "stop_limit"):
                    execution_type_out = et
                ep = ta_hints.get("entry_price")
                if ep is not None:
                    try:
                        epf = float(ep)
                        if epf > 0:
                            entry_price_out = epf
                    except Exception:
                        pass
                if _env_bool("AI_TRADINGAGENTS_MERGE_STOPS_FROM_TA", True):
                    try:
                        sl_h = ta_hints.get("stop_loss")
                        if sl_h is not None and float(sl_h) > 0:
                            stop_loss = float(sl_h)
                    except Exception:
                        pass
                    try:
                        tp_h = ta_hints.get("take_profit")
                        if tp_h is not None and float(tp_h) > 0:
                            take_profit = float(tp_h)
                    except Exception:
                        pass
                if execution_type_out and entry_price_out:
                    reason += f" [TradingAgents {execution_type_out.upper()} @ {entry_price_out}]"
                elif execution_type_out:
                    reason += f" [TradingAgents {execution_type_out.upper()} — prix via marché/ATR]"
        except Exception as e:
            logger.debug("TradingAgents exec merge: %s", e)

    stair_client_eid: Optional[str] = None
    if request.stair_detected:
        sym_st = str(request.symbol or "")
        sd_st = (request.stair_direction or "").strip().upper() or synth_stair_direction_for_symbol(sym_st)
        if sd_st:
            stair_client_eid = (request.stair_client_event_id or "").strip() or str(uuid4())
            pk_st = (request.stair_pattern_kinds or "").strip()
            feats_st = dict(request.stair_features or {})
            try:
                feats_st.setdefault("rsi", request.rsi)
                feats_st.setdefault("atr", request.atr)
            except Exception:
                pass
            q_st = _stair_compute_quality_from_features(feats_st)
            wr_st, _n_st = await _stair_empirical_win_rate(sym_st, sd_st, pk_st if pk_st else None)
            payload_st = {
                "client_event_id": stair_client_eid,
                "symbol": sym_st,
                "category": _stair_category_for_symbol(sym_st),
                "direction": sd_st,
                "timeframe": "M1",
                "pattern_kinds": pk_st or None,
                "quality_score": q_st,
                "empirical_win_rate_at_detect": wr_st,
                "features": feats_st,
                "ai_action": action,
                "ai_confidence": float(confidence),
                "outcome": "open",
                "source": "decision_endpoint",
            }
            asyncio.create_task(_insert_stair_detection_supabase(payload_st))
    
    # 13. Créer la réponse enrichie
    hold_diagnostic = ""
    if action == "hold":
        hold_diagnostic = (reason or "")[:280]
        logger.info(
            "⏸️ HOLD %s | buy=%.3f sell=%.3f | funnel=%s | ml=%s",
            request.symbol,
            buy_score,
            sell_score,
            funnel.get("action", "?"),
            ml_result.get("ml_reason", ""),
        )

    meta_out = {
        "original_decision": ml_result["original_decision"],
        "original_confidence": ml_result["original_confidence"],
        "ml_enhanced": ml_result["ml_applied"],
        "ml_reason": ml_result["ml_reason"],
        "base_scores": {"buy": buy_score, "sell": sell_score},
        "market_data": market_data,
        "confidence_decimal": confidence,
        "confidence_percentage": confidence_percentage,
        "spike_probability": market_data.get("spike_probability", 0.0),
        "stair_detected": bool(request.stair_detected),
        "stair_client_event_id": stair_client_eid,
        "chart_pattern_model": chart_pattern_signal,
        "funnel_mtf": funnel,
        "qwen_blend": qwen_meta,
        "final_decision": {"action": action, "confidence": confidence_percentage},
        "hold_diagnostic": hold_diagnostic,
    }
    if confluence_detail:
        meta_out["indicator_confluence"] = confluence_detail
    if divergence_meta:
        meta_out["divergence_strategy"] = divergence_meta
    if entry_price_out is not None or execution_type_out:
        meta_out["tradingagents_execution"] = {
            "entry_price": entry_price_out,
            "execution_type": execution_type_out,
        }
    exec_type_final = execution_type_out
    if divergence_meta and action in ("buy", "sell"):
        exec_type_final = "market"

    # Calcul risque pour $50 capital / 2% par trade
    _risk = _calc_risk_info(
        action=action,
        entry=entry_price_out or getattr(request, "ask", None) or getattr(request, "bid", None),
        stop_loss=stop_loss,
        atr=getattr(request, "atr", None),
        symbol=request.symbol,
        capital=50.0,
        risk_pct=2.0,
    )
    meta_out["risk_info"] = _risk

    response = DecisionResponse(
        action=action,
        confidence=confidence_percentage,  # Décimale 0-1 (MT5 affiche *100)
        reason=reason,
        stop_loss=stop_loss,
        take_profit=take_profit,
        entry_price=entry_price_out,
        execution_type=exec_type_final,
        timestamp=datetime.now().isoformat(),
        model_used=(
            "technical_ml_divergence_blend"
            if divergence_meta
            else "technical_ml_qwen_blend"
        ),
        predicted_prices=predicted_prices,
        alignment=alignment,
        coherence=coherence,
        metadata=meta_out,
        recommended_lot=_risk.get("recommended_lot"),
        max_loss_usd=_risk.get("max_loss_usd"),
        risk_info=_risk,
    )

    set_simplified_tf_cached_decision(request, response)

    # 11. Sauvegarder la décision dans Supabase (local OU cloud) si les clés sont disponibles
    try:
        await save_decision_to_supabase(request, response, ml_result)
    except Exception as e:
        logger.error(f"❌ Erreur sauvegarde décision (persistance): {e}")
    
    return response


async def _push_prediction_to_supabase(
    request: DecisionRequest,
    response: DecisionResponse,
    ml_result: Optional[dict] = None,
):
    """
    Write every AI prediction to the database (AWS RDS or Supabase fallback).
    Called from decision_simplified and /decision so you can monitor the robot's decisions in the database.
    """
    # Préparer les métadonnées
    request_data = {
        "bid": request.bid,
        "ask": request.ask,
        "rsi": request.rsi,
        "ema_fast_m1": request.ema_fast_m1,
        "ema_slow_m1": request.ema_slow_m1,
        "ema_fast_h1": request.ema_fast_h1,
        "ema_slow_h1": request.ema_slow_h1,
        "ema_fast_m5": request.ema_fast_m5,
        "ema_slow_m5": request.ema_slow_m5,
        "atr": request.atr,
    }
    if ml_result:
        metadata = {
            "original_decision": ml_result.get("original_decision", response.action),
            "original_confidence": ml_result.get("original_confidence", response.confidence),
            "ml_enhanced": ml_result.get("ml_applied", False),
            "ml_reason": ml_result.get("ml_reason", ""),
            "request_data": request_data,
        }
    else:
        metadata = {
            "original_decision": response.action,
            "original_confidence": response.confidence,
            "ml_enhanced": False,
            "ml_reason": "",
            "request_data": request_data,
        }

    decision_data = {
        "symbol": request.symbol,
        "timeframe": "M1",
        "prediction": response.action,
        "confidence": response.confidence / 100.0,  # Convert to decimal for DB
        "reason": (response.reason or "")[:2000],
        "model_used": getattr(response, "model_used", None) or "technical_ml_enhanced",
        "metadata": metadata,
    }

    # Utiliser AWS RDS si disponible, sinon fallback vers Supabase
    if AWS_RDS_AVAILABLE and _env_bool("USE_SUPABASE", False) == False:
        try:
            import json
            # Convertir metadata en JSON string pour PostgreSQL JSONB
            decision_data["metadata"] = json.dumps(decision_data["metadata"])
            result_id = aws_rds_client.insert("predictions", decision_data)
            if result_id:
                logger.debug(f"✅ Prediction enregistrée dans AWS RDS (ID: {result_id})")
            return
        except Exception as e:
            logger.error(f"❌ Erreur AWS RDS prediction: {e}")
            # Ne pas fallback vers Supabase ici, juste logger l'erreur
            return

    # Fallback Supabase (si activé)
    supabase_url = os.getenv("SUPABASE_URL", "https://bpzqnooiisgadzicwupi.supabase.co")
    supabase_key = os.getenv("SUPABASE_SERVICE_KEY") or os.getenv("SUPABASE_ANON_KEY")
    if not supabase_url or not supabase_key:
        return

    try:
        import httpx
        decision_data["confidence"] = response.confidence  # Garder en pourcentage pour Supabase
        async with httpx.AsyncClient() as client:
            resp = await client.post(
                f"{supabase_url}/rest/v1/predictions",
                json=decision_data,
                headers={
                    "apikey": supabase_key,
                    "Authorization": f"Bearer {supabase_key}",
                    "Content-Type": "application/json",
                    "Prefer": "return=minimal",
                },
                timeout=10.0,
            )
            if resp.status_code != 201:
                logger.warning(f"Predictions table HTTP {resp.status_code}: {resp.text[:200]}")
    except Exception as e:
        logger.debug("predictions persist: %s", e)


async def save_decision_to_supabase(request: DecisionRequest, response: DecisionResponse, ml_result: dict):
    """Sauvegarder la décision améliorée dans la base de données (AWS RDS ou Supabase fallback)."""
    await _push_prediction_to_supabase(request, response, ml_result)

    # (Important) Par défaut on NE doit PAS écrire un proxy dans `model_metrics` à chaque prédiction,
    # sinon on écrase les métriques réelles produites par le trainer (integrated_ml_trainer / continuous_ml_trainer).
    # Tu peux réactiver ce comportement via env var pour debug.
    enable_proxy = os.getenv("AI_ENABLE_MODEL_METRICS_PROXY_FROM_PREDICTIONS", "false").lower() == "true"

    if not enable_proxy:
        return

    # Extraire une "accuracy" proxy à partir de la confiance (décimale)
    accuracy_decimal = None
    meta = getattr(response, "metadata", None)
    if isinstance(meta, dict) and "confidence_decimal" in meta:
        try:
            accuracy_decimal = float(meta.get("confidence_decimal"))
        except (TypeError, ValueError):
            accuracy_decimal = None
    if accuracy_decimal is None:
        try:
            # response.confidence est renvoyée en pourcentage (0-100)
            accuracy_decimal = float(response.confidence) / 100.0
        except Exception:
            accuracy_decimal = 0.5

    if not (0.0 <= accuracy_decimal <= 1.0):
        accuracy_decimal = 0.5

    metrics_payload = {
        "symbol": request.symbol,
        "timeframe": "M1",
        "model_type": response.model_used or "technical_ml_enhanced",
        "accuracy": float(accuracy_decimal),
        "metadata": {
            "last_action": response.action,
            "last_confidence_pct": float(response.confidence),
            "reason_sample": response.reason[:240] if isinstance(response.reason, str) else "",
            "source": "predictions_proxy",
        },
    }

    # Utiliser AWS RDS si disponible
    if AWS_RDS_AVAILABLE and _env_bool("USE_SUPABASE", False) == False:
        try:
            import json
            metrics_payload["metadata"] = json.dumps(metrics_payload["metadata"])
            result_id = aws_rds_client.insert("model_metrics", metrics_payload)
            if result_id:
                logger.info(f"✅ model_metrics proxy insérée dans AWS RDS pour {request.symbol} accuracy={accuracy_decimal:.3f}")
            return
        except Exception as e:
            logger.debug(f"Erreur lors de la sauvegarde proxy model_metrics AWS RDS: {e}")
            return

    # Fallback Supabase
    supabase_url = os.getenv("SUPABASE_URL", "https://bpzqnooiisgadzicwupi.supabase.co")
    supabase_key = os.getenv("SUPABASE_SERVICE_KEY") or os.getenv("SUPABASE_ANON_KEY")
    if not supabase_url or not supabase_key:
        return

    headers = {
        "apikey": supabase_key,
        "Authorization": f"Bearer {supabase_key}",
        "Content-Type": "application/json",
        "Prefer": "return=representation",
    }

    try:
        import httpx
        async with httpx.AsyncClient() as client:
            r_metrics = await client.post(
                f"{supabase_url}/rest/v1/model_metrics",
                json=metrics_payload,
                headers=headers,
                timeout=10.0,
            )
            if r_metrics.status_code not in (200, 201):
                logger.error(
                    "model_metrics proxy: statut %s body=%s payload=%s",
                    r_metrics.status_code,
                    r_metrics.text,
                    metrics_payload,
                )
            else:
                logger.info(
                    "✅ model_metrics proxy insérée pour %s accuracy=%.3f",
                    request.symbol,
                    metrics_payload["accuracy"],
                )
    except Exception as e:
        logger.debug(f"Erreur lors de la sauvegarde proxy model_metrics: {e}")


async def fetch_supabase_ml_context(symbol: str, timeframe: str = "M1") -> Dict[str, Any]:
    """
    Requête Supabase: model_metrics, symbol_calibration, trade_feedback pour ce symbole.
    Utilisé pour que le robot prenne ses décisions sur la base du ML et apprenne des erreurs.
    """
    import httpx
    supabase_url = os.getenv("SUPABASE_URL", "https://bpzqnooiisgadzicwupi.supabase.co")
    supabase_key = os.getenv("SUPABASE_SERVICE_KEY") or os.getenv("SUPABASE_ANON_KEY")
    if not supabase_key:
        return {}
    sym_enc = symbol.replace(" ", "%20")
    headers = {"apikey": supabase_key, "Authorization": f"Bearer {supabase_key}"}
    out = {
        "model_accuracy": 0.5,
        "calibration_wins": 0,
        "calibration_total": 0,
        "drift_factor": 1.0,
        "recent_win_rate": 0.5,
        "recent_count": 0,
    }
    async with httpx.AsyncClient() as client:
        try:
            # Dernière métrique modèle pour ce symbole
            r1 = await client.get(
                f"{supabase_url}/rest/v1/model_metrics",
                params={"symbol": f"eq.{symbol}", "timeframe": f"eq.{timeframe}", "order": "training_date.desc", "limit": "1"},
                headers=headers,
                timeout=5.0,
            )
            if r1.status_code == 200 and r1.json():
                row = r1.json()[0]
                out["model_accuracy"] = float(row.get("accuracy", 0.5))
                meta = row.get("metadata")
                if isinstance(meta, dict):
                    out["drift_factor"] = float(meta.get("drift_factor", 1.0))
                elif isinstance(meta, str):
                    try:
                        m = json.loads(meta)
                        out["drift_factor"] = float(m.get("drift_factor", 1.0))
                    except Exception:
                        pass
        except Exception:
            pass
        try:
            r2 = await client.get(
                f"{supabase_url}/rest/v1/symbol_calibration",
                params={"symbol": f"eq.{symbol}", "limit": "1"},
                headers=headers,
                timeout=5.0,
            )
            if r2.status_code == 200 and r2.json():
                row = r2.json()[0]
                out["calibration_wins"] = int(row.get("wins", 0))
                out["calibration_total"] = int(row.get("total", 0))
                out["drift_factor"] = float(row.get("drift_factor", 1.0))
        except Exception:
            pass
        try:
            r3 = await client.get(
                f"{supabase_url}/rest/v1/trade_feedback",
                params={"symbol": f"eq.{symbol}", "order": "created_at.desc", "limit": "50"},
                headers=headers,
                timeout=5.0,
            )
            if r3.status_code == 200 and r3.json():
                rows = r3.json()
                wins = sum(1 for x in rows if x.get("is_win") is True)
                out["recent_count"] = len(rows)
                out["recent_win_rate"] = wins / len(rows) if rows else 0.5
        except Exception:
            pass
    return out



