@app.get("/symbols/propice/status")
async def get_symbol_propice_status(symbol: str, timeframe: str = "M1", lookback_days: int = 14):
    """
    Statut détaillé d'un symbole (profil horaire + score maintenant) avec fallback cache.
    """
    symbol = (symbol or "").strip()
    timeframe = (timeframe or "M1").strip().upper()
    if not symbol:
        raise HTTPException(status_code=400, detail="symbol requis")
    if timeframe != "M1":
        raise HTTPException(status_code=400, detail="timeframe supporté: M1 uniquement")
    lookback_days = int(lookback_days or 14)

    now_hour_utc = int(datetime.utcnow().hour)

    # 1) cache local
    cached_profile = symbol_hour_profile_cache.get((symbol, timeframe, lookback_days))
    cached_status = symbol_hour_status_cache.get((symbol, timeframe))
    if cached_profile and cached_profile.get("rows"):
        rows = cached_profile["rows"]
        now_row = next((r for r in rows if int(r.get("hour_utc", -1)) == now_hour_utc), None)
        return {
            "symbol": symbol,
            "timeframe": timeframe,
            "lookback_days": lookback_days,
            "now_hour_utc": now_hour_utc,
            "profile_rows": rows,
            "now": {
                "propice_score": float((now_row or {}).get("propice_score", 0.0) or 0.0),
                "trend_bias": float((now_row or {}).get("trend_bias", 0.0) or 0.0),
                "reason": (cached_status or {}).get("reason", "cache"),
                "computed_at": (cached_status or {}).get("computed_at"),
            },
            "source": "cache",
        }

    # 2) Supabase fallback
    try:
        supabase_url, supabase_key = _get_supabase_config(strict=True)
        import httpx
        headers = {
            "apikey": supabase_key,
            "Authorization": f"Bearer {supabase_key}",
        }
        params = {
            "symbol": f"eq.{symbol}",
            "timeframe": f"eq.{timeframe}",
            "lookback_days": f"eq.{lookback_days}",
            "order": "hour_utc.asc",
        }
        async with httpx.AsyncClient(timeout=10.0) as client:
            r = await client.get(f"{supabase_url}/rest/v1/symbol_hour_profile", headers=headers, params=params)
        if r.status_code not in (200, 206):
            raise RuntimeError(f"Supabase HTTP {r.status_code}: {r.text[:200]}")
        rows = r.json() if r.text else []
        now_row = next((rr for rr in rows if int(rr.get("hour_utc", -1)) == now_hour_utc), None)
        return {
            "symbol": symbol,
            "timeframe": timeframe,
            "lookback_days": lookback_days,
            "now_hour_utc": now_hour_utc,
            "profile_rows": rows,
            "now": {
                "propice_score": float((now_row or {}).get("propice_score", 0.0) or 0.0),
                "trend_bias": float((now_row or {}).get("trend_bias", 0.0) or 0.0),
                "reason": "supabase",
            },
            "source": "supabase",
        }
    except Exception as e:
        import httpx as _hx
        if isinstance(e, _hx.RequestError):
            raise HTTPException(
                status_code=503,
                detail=f"Supabase injoignable ({type(e).__name__}). Vérifie URL, clé API et connexion.",
            )
        raise HTTPException(status_code=503, detail=f"Statut indisponible (cache vide et Supabase KO): {e}")


@app.get("/symbols/propice/top")
async def get_symbols_propice_top(timeframe: str = "M1", lookback_days: int = 14, n: int = 5):
    """
    Retourne les Top N symbols propices pour l'heure UTC actuelle.
    Fallback: cache local si Supabase indisponible.
    """
    timeframe = (timeframe or "M1").strip().upper()
    if timeframe != "M1":
        raise HTTPException(status_code=400, detail="timeframe supporté: M1 uniquement")
    lookback_days = int(lookback_days or 14)
    n = max(1, min(int(n or 5), 50))
    now_hour_utc = int(datetime.utcnow().hour)

    # 1) essayer Supabase trade_feedback d'abord (source-of-truth = résultats réels)
    try:
        payload = await _compute_propice_top_from_trade_feedback(timeframe, lookback_days, n, now_hour_utc)
        rows = payload.get("rows") or []
        if rows:
            return {
                "timeframe": timeframe,
                "lookback_days": lookback_days,
                "now_hour_utc": now_hour_utc,
                "n": n,
                "rows": rows,
                "source": payload.get("source", "supabase_trade_feedback"),
            }
    except Exception:
        pass

    # 2) fallback Supabase symbol_hour_profile (profil volatilité/spike basé M1)
    try:
        supabase_url, supabase_key = _get_supabase_config(strict=True)
        import httpx
        headers = {
            "apikey": supabase_key,
            "Authorization": f"Bearer {supabase_key}",
        }
        params = {
            "timeframe": f"eq.{timeframe}",
            "lookback_days": f"eq.{lookback_days}",
            "hour_utc": f"eq.{now_hour_utc}",
            "order": "propice_score.desc",
            "limit": str(n),
        }
        async with httpx.AsyncClient(timeout=10.0) as client:
            r = await client.get(f"{supabase_url}/rest/v1/symbol_hour_profile", headers=headers, params=params)
        if r.status_code in (200, 206):
            rows = r.json() if r.text else []
            return {
                "timeframe": timeframe,
                "lookback_days": lookback_days,
                "now_hour_utc": now_hour_utc,
                "n": n,
                "rows": rows,
                "source": "supabase_symbol_hour_profile",
            }
    except Exception:
        pass

    # 3) fallback cache
    out = []
    for (sym, tf, lb), payload in symbol_hour_profile_cache.items():
        if tf != timeframe or lb != lookback_days:
            continue
        rows = payload.get("rows") or []
        now_row = next((r for r in rows if int(r.get("hour_utc", -1)) == now_hour_utc), None)
        if not now_row:
            continue
        out.append({
            "symbol": sym,
            "timeframe": timeframe,
            "lookback_days": lookback_days,
            "hour_utc": now_hour_utc,
            "propice_score": float(now_row.get("propice_score", 0.0) or 0.0),
            "trend_bias": float(now_row.get("trend_bias", 0.0) or 0.0),
            "reason": "cache",
        })
    out.sort(key=lambda r: float(r.get("propice_score", 0.0) or 0.0), reverse=True)
    return {
        "timeframe": timeframe,
        "lookback_days": lookback_days,
        "now_hour_utc": now_hour_utc,
        "n": n,
        "rows": out[:n],
        "source": "cache",
    }

@app.get("/logs")
async def get_logs(limit: int = 100):
    """Récupère les dernières lignes du log"""
    try:
        if not LOG_FILE.exists():
            return {"logs": [], "message": "Aucun log disponible"}

        with open(LOG_FILE, "r", encoding="utf-8") as f:
            lines = f.readlines()
            recent_lines = lines[-limit:] if len(lines) > limit else lines

        return {
            "logs": [line.strip() for line in recent_lines],
            "total_lines": len(lines),
            "returned_lines": len(recent_lines)
        }
    except Exception as e:
        logger.error(f"Erreur lecture logs: {e}")
        return {"logs": [], "error": str(e)}


# ===== TRADINGVIEW WEBHOOK INTEGRATION =====

class TradingViewSignal(BaseModel):
    """Modèle pour les signaux TradingView reçus via webhook"""
    symbol: str = Field(..., description="Symbole du trading pair (ex: EURUSD)")
    timeframe: str = Field("M1", description="Timeframe (M1, M5, M15, M30, H1, H4, D1)")
    action: str = Field(..., description="Action: BUY, SELL, ou CLOSE")
    confidence: float = Field(default=0.75, ge=0.0, le=1.0, description="Confiance du signal (0-1)")
    price: Optional[float] = Field(None, description="Prix actuel de déclenchement")
    stop_loss: Optional[float] = Field(None, description="Stop Loss sugéré")
    take_profit: Optional[float] = Field(None, description="Take Profit suggéré")
    reason: Optional[str] = Field(None, description="Raison/analyse du signal")
    alert_message: Optional[str] = Field(None, description="Message brut de l'alerte TradingView")
    custom_data: Optional[Dict[str, Any]] = Field(None, description="Données personnalisées additionnelles")


@app.post("/webhook/tradingview")
async def webhook_tradingview(signal: TradingViewSignal):
    """
    Endpoint webhook pour recevoir les signaux TradingView.

    Usage dans TradingView Pine Script:
    ```
    alertmessage = json.stringify({
        "symbol": syminfo.prefix + syminfo.basecurrency,
        "timeframe": timeframe.period,
        "action": "BUY",
        "confidence": 0.85,
        "price": close,
        "stop_loss": close - (atr * 2),
        "take_profit": close + (atr * 3),
        "reason": "PERFECT Signal - FVG + OB Breakout"
    })
    alert(alertmessage)
    ```
    """
    try:
        start_time = time.time()

        # Validation
        symbol = (signal.symbol or "").strip().upper()
        if not validate_symbol(symbol):
            raise HTTPException(
                status_code=400,
                detail=f"Symbole invalide: {symbol}. Format: [A-Z0-9_]{{2,20}}"
            )

        timeframe = (signal.timeframe or "M1").strip().upper()
        if not validate_timeframe(timeframe):
            raise HTTPException(
                status_code=400,
                detail=f"Timeframe non supportée: {timeframe}. Supportés: {VALID_TIMEFRAMES}"
            )

        action = (signal.action or "").strip().upper()
        if action not in ("BUY", "SELL", "CLOSE"):
            raise HTTPException(
                status_code=400,
                detail=f"Action invalide: {action}. Doit être: BUY, SELL, CLOSE"
            )

        confidence = float(signal.confidence or 0.75)
        confidence = max(0.0, min(1.0, confidence))

        logger.info(
            f"📊 TradingView Signal reçu: {symbol} {timeframe} {action} "
            f"(confiance: {confidence:.0%}, prix: {signal.price})"
        )

        # Construire le payload d'analyse compatible avec la pipeline existante
        analysis_payload = {
            "symbol": symbol,
            "timeframe": timeframe,
            "direction": action,
            "action": action,
            "confidence": confidence,
            "current_price": signal.price or 0.0,
            "stop_loss": signal.stop_loss or 0.0,
            "take_profit": signal.take_profit or 0.0,
            "reason": signal.reason or "TradingView Signal",
            "source": "tradingview_webhook",
            "timestamp": datetime.utcnow().isoformat(),
        }

        if signal.custom_data:
            analysis_payload.update(signal.custom_data)

        # Validation du verdict avec la logique SMC existante
        decision_request = DecisionRequest(
            symbol=symbol,
            timeframe=timeframe,
            timestamp=datetime.utcnow().isoformat(),
            data=analysis_payload,
            rsi=None,
            macd=None,
            atr=None,
        )

        # Traiter via la pipeline décision360 existante
        result = await process_analysis_360(analysis_payload)

        process_time = time.time() - start_time

        # Logger le résultat
        logger.info(
            f"✅ TradingView Signal traité: {symbol} → {result.get('status')} "
            f"(temps: {process_time:.3f}s)"
        )

        # Retourner la décision avec métadonnées
        return {
            "status": "SUCCESS",
            "symbol": symbol,
            "action": action,
            "timeframe": timeframe,
            "confidence": confidence,
            "decision": result,
            "source": "tradingview",
            "processed_at": datetime.utcnow().isoformat(),
            "processing_time_ms": int(process_time * 1000),
        }

    except HTTPException:
        raise
    except Exception as e:
        logger.error(f"❌ Erreur webhook TradingView: {e}", exc_info=True)
        raise HTTPException(
            status_code=500,
            detail=f"Erreur traitement webhook TradingView: {str(e)[:100]}"
        )


