# Pause globale après N gains consécutifs sans perte (performance exceptionnelle)
_WIN_STREAK: list = []
WIN_STREAK_THRESHOLD = 5           # 5 wins d'affilée → pause 2h
WIN_STREAK_PAUSE_SEC = 2 * 3600    # 2 heures
_WIN_STREAK_PAUSE_UNTIL: float = 0.0

# Gate probabilité élevée (anti-hazard)
MIN_ENTRY_PROBABILITY_PCT = 72.0
MIN_GOM_VERDICT_NUM_ABS = 2
HIGH_PROB_BC_MIN_CONF = 70.0
MIN_COG_STRENGTH = 0.50
MIN_COG_CONFIDENCE = 0.55

def _record_win_streak_from_profit(profit: float, symbol: str = "") -> None:
    """Met à jour la série de gains et déclenche la pause performance si seuil atteint."""
    import time as _ws_time
    global _WIN_STREAK, _WIN_STREAK_PAUSE_UNTIL

    try:
        p = float(profit or 0)
    except (TypeError, ValueError):
        return

    if p < 0:
        _WIN_STREAK = []
        logger.info("[WinStreak] Série réinitialisée après perte%s", f" ({symbol})" if symbol else "")
        return

    if p <= 0:
        return

    _WIN_STREAK.append(_ws_time.time())
    logger.info(
        "[WinStreak] Gain %s profit=%.2f — série: %s/%s",
        symbol or "?",
        p,
        len(_WIN_STREAK),
        WIN_STREAK_THRESHOLD,
    )
    if len(_WIN_STREAK) >= WIN_STREAK_THRESHOLD:
        _WIN_STREAK_PAUSE_UNTIL = _ws_time.time() + WIN_STREAK_PAUSE_SEC
        _WIN_STREAK = []
        resume_ts = datetime.utcfromtimestamp(_WIN_STREAK_PAUSE_UNTIL).strftime("%H:%M UTC")
        logger.warning(
            "[WinStreak] %s gains consécutifs — PAUSE %sh jusqu'à %s",
            WIN_STREAK_THRESHOLD,
            WIN_STREAK_PAUSE_SEC // 3600,
            resume_ts,
        )


def _check_win_streak_pause() -> Tuple[bool, Optional[str]]:
    import time as _ws_time
    if _ws_time.time() >= _WIN_STREAK_PAUSE_UNTIL:
        return True, None
    remaining = int(_WIN_STREAK_PAUSE_UNTIL - _ws_time.time())
    hours = remaining // 3600
    mins = (remaining % 3600) // 60
    return False, f"Pause performance win-streak — {hours}h{mins:02d}m restantes"


def _validate_gom_confluence(symbol: str, direction: str, gom_verdict: Optional[str],
                               gom_score_buy: Optional[float], gom_score_sell: Optional[float]) -> dict:
    """
    Valide la confluence entre la direction du signal et le verdict GOM KOLA.
    Règles :
      - Signal SELL + GOM BUY  → correction probable, réduire confiance, warning
      - Signal BUY  + GOM SELL → correction probable, réduire confiance, warning
      - Signal aligné avec GOM → boost confiance +10%
      - GOM WAIT               → neutre, pas de modification
    """
    stored = _GOM_VERDICT_STORE.get(symbol.upper(), {})
    verdict = (gom_verdict or stored.get("verdict") or "UNKNOWN").upper()
    score_buy  = gom_score_buy  if gom_score_buy  is not None else stored.get("score_buy",  0.0)
    score_sell = gom_score_sell if gom_score_sell is not None else stored.get("score_sell", 0.0)

    result = {"gom_verdict": verdict, "gom_action": "NONE", "gom_warning": None, "confidence_delta": 0.0}

    if verdict == "UNKNOWN" or verdict == "WAIT":
        result["gom_action"] = "NEUTRAL"
        return result

    # Conflit : signal opposé au verdict GOM
    if direction == "SELL" and verdict == "BUY":
        gap = score_buy - score_sell
        result["gom_action"]     = "CONFLICT"
        result["confidence_delta"] = -0.15 if gap >= 2.0 else -0.08
        result["gom_warning"]    = (
            f"⚠️ CONFLIT GOM : signal SELL mais verdict GOM=BUY (buy={score_buy:.1f} sell={score_sell:.1f}). "
            f"Probable correction — réduire lot, élargir SL ou attendre retest OB baissier."
        )
    elif direction == "BUY" and verdict == "SELL":
        gap = score_sell - score_buy
        result["gom_action"]     = "CONFLICT"
        result["confidence_delta"] = -0.15 if gap >= 2.0 else -0.08
        result["gom_warning"]    = (
            f"⚠️ CONFLIT GOM : signal BUY mais verdict GOM=SELL (sell={score_sell:.1f} buy={score_buy:.1f}). "
            f"Probable correction — réduire lot, élargir SL ou attendre retest OB haussier."
        )
    # Alignement : signal = verdict GOM → boost
    elif direction == verdict:
        result["gom_action"]     = "ALIGNED"
        result["confidence_delta"] = 0.10
        result["gom_warning"]    = None

    return result

@app.post("/pending-order")
async def set_pending_order(payload: PendingOrderPayload):
    direction = (payload.action or payload.recommendation or "NEUTRAL").upper()
    sym = payload.symbol.upper().strip()

    # Validation croisée GOM KOLA
    gom_check = _validate_gom_confluence(
        sym, direction,
        payload.gom_verdict, payload.gom_score_buy, payload.gom_score_sell
    )
    base_conf = payload.confidence or 0.75
    final_conf = max(0.0, min(1.0, base_conf + gom_check["confidence_delta"]))

    if gom_check["gom_warning"]:
        logger.warning(f"[PendingOrder] {sym} {gom_check['gom_warning']}")

    # Gate bc_heure — plage UTC propice (Boom/Crash, pipeline inclus)
    bc_ok, bc_reason, bc_status = _check_bc_hour_gate(sym)
    if not bc_ok:
        from fastapi import HTTPException
        logger.warning(f"[PendingOrder] {sym} bloque BC heure: {bc_reason}")
        raise HTTPException(status_code=403, detail=bc_reason)

    cog_ok, cog_reason = _check_cognition_gate(sym, direction)
    if not cog_ok:
        from fastapi import HTTPException
        logger.warning(f"[PendingOrder] {sym} bloque cognition: {cog_reason}")
        raise HTTPException(status_code=403, detail=cog_reason)

    prob_ok, prob_reason = _check_probability_gate(sym, direction)
    if not prob_ok:
        from fastapi import HTTPException
        logger.warning(f"[PendingOrder] {sym} bloque probabilité: {prob_reason}")
        raise HTTPException(status_code=403, detail=prob_reason)

    # Mise à jour store verdict GOM si fourni dans ce payload
    if payload.gom_verdict:
        _GOM_VERDICT_STORE[sym] = {
            "verdict":    payload.gom_verdict.upper(),
            "score_buy":  payload.gom_score_buy  or 0.0,
            "score_sell": payload.gom_score_sell or 0.0,
            "spike_pct":  payload.gom_spike_pct  or 0.0,
            "timestamp":  datetime.utcnow().isoformat(),
        }

    reasoning_enriched = (payload.reasoning or "") + (
        f" | GOM={gom_check['gom_verdict']} ({gom_check['gom_action']})" +
        (f" | {gom_check['gom_warning']}" if gom_check["gom_warning"] else "")
    )
    if bc_status.get("bc_applicable"):
        reasoning_enriched += (
            f" | BC UTC{bc_status.get('bc_hour_utc')} "
            f"{bc_status.get('bc_confidence', 0):.0f}% "
            f"{'OK' if bc_status.get('bc_tradeable') else 'OFF'}"
        )

    # Cooldown post-perte : refuser un nouvel ordre si une perte récente existe
    import time as _t
    _loss_ts = _LOSS_COOLDOWN_STORE.get(sym, 0)
    if _t.time() - _loss_ts < LOSS_COOLDOWN_SEC:
        _remaining = int(LOSS_COOLDOWN_SEC - (_t.time() - _loss_ts))
        from fastapi import HTTPException
        raise HTTPException(
            status_code=429,
            detail=f"{sym} en cooldown post-perte — {_remaining}s restantes ({LOSS_COOLDOWN_SEC//60}min)"
        )

    _ws_ok, _ws_reason = _check_win_streak_pause()
    if not _ws_ok:
        from fastapi import HTTPException
        logger.warning(f"[PendingOrder] {sym} bloque win-streak: {_ws_reason}")
        raise HTTPException(status_code=429, detail=_ws_reason)

    # Dedup gate — rejeter si un ordre actif existe déjà pour ce symbole
    # Exception : source=pipeline a priorité et remplace toujours l'ordre GOM auto
    _incoming_source = (payload.source or "").lower()
    _existing = _PENDING_ORDER_STORE.get(sym)
    if _existing and _existing.get("status") in ("ready", "executing"):
        _existing_source = (_existing.get("source") or "").lower()
        _age_s = (datetime.utcnow() - datetime.fromisoformat(_existing["timestamp"])).total_seconds() if _existing.get("timestamp") else 9999
        _is_pipeline = _incoming_source in ("pipeline", "pipeline_ta", "pipeline_hourly")
        _is_gom_auto = _existing_source in ("gom_tv_sync", "mt5_live", "")
        # Un ordre executing non-confirmé depuis > 5min est abandonné (MT5 n'a pas confirmé)
        _is_executing_stale = _existing.get("status") == "executing" and _age_s > 300
        # Pipeline remplace toujours les ordres GOM auto (ready ou executing)
        # Pipeline remplace aussi tout ordre executing stale > 5min non confirmé par MT5
        if (_is_pipeline and _is_gom_auto) or _is_executing_stale:
            logger.info(f"[PendingOrder] {sym} {_incoming_source} remplace ordre {_existing_source}/{_existing.get('status')} (age={_age_s:.0f}s, stale={_is_executing_stale})")
        elif _age_s < 300:  # moins de 5 minutes
            from fastapi import HTTPException
            raise HTTPException(
                status_code=409,
                detail=f"{sym} already has an active pending order (status={_existing['status']}, age={_age_s:.0f}s, source={_existing_source}) — reset first"
            )
        else:
            logger.info(f"[PendingOrder] {sym} ordre existant expiré ({_age_s:.0f}s > 300s) — remplacement autorisé")

    _raw_status = (payload.status or "ready").lower()
    _src = payload.source or ""

    # Apply spike anticipation if available
    _entry_price = payload.entry_price
    _stop_loss = payload.stop_loss
    _take_profit = payload.take_profit
    _anticipation_applied = False
    _anticipation_distance = 0.0

    if SPIKE_ANTICIPATION_AVAILABLE and _spike_anticipator:
        logger.debug(f"[SPIKE] Available and enabled for {sym}")
        try:
            # Get RSI from payload if available (check both normal attrs and extra fields)
            _rsi = getattr(payload, 'rsi', None)
            if _rsi is None and hasattr(payload, '__pydantic_extra__'):
                _rsi = payload.__pydantic_extra__.get('rsi')

            # Determine volatility regime (optional)
            _volatility = getattr(payload, 'volatility_regime', None)
            if _volatility is None and hasattr(payload, '__pydantic_extra__'):
                _volatility = payload.__pydantic_extra__.get('volatility_regime')

            # Apply anticipation
            anticipated = _spike_anticipator.format_order_with_anticipation(
                symbol=sym,
                action=direction,
                base_entry=payload.entry_price,
                base_sl=payload.stop_loss,
                base_tp=payload.take_profit,
                verdict_strength=gom_check["gom_verdict"],
                rsi=_rsi,
                volatility_regime=_volatility,
            )

            if anticipated.get("anticipation_applied", False):
                _entry_price = anticipated.get("entry", payload.entry_price)
                _stop_loss = anticipated.get("sl", payload.stop_loss)
                _take_profit = anticipated.get("tp", payload.take_profit)
                _anticipation_applied = True
                _anticipation_distance = anticipated.get("anticipation_distance_pips", 0.0)
                logger.info(
                    f"[SPIKE] {sym} Anticipation applied: {_anticipation_distance:.1f} pips "
                    f"(entry {payload.entry_price} -> {_entry_price})"
                )
        except Exception as e:
            logger.warning(f"[SPIKE] Anticipation failed for {sym}: {e} (using original prices)")

    _PENDING_ORDER_STORE[sym] = {
        "symbol":         sym,
        "recommendation": direction,
        "action":         direction,
        "entry_price":    _entry_price,
        "stop_loss":      _stop_loss,
        "take_profit":    _take_profit,
        "lot":            payload.lot,
        "execution_type": payload.execution_type,
        "confidence":     final_conf,
        "reasoning":      reasoning_enriched,
        "gom_verdict":    gom_check["gom_verdict"],
        "gom_action":     gom_check["gom_action"],
        "gom_warning":    gom_check["gom_warning"],
        "bc_hour_utc":    bc_status.get("bc_hour_utc"),
        "bc_confidence":  bc_status.get("bc_confidence"),
        "bc_tradeable":   bc_status.get("bc_tradeable"),
        "source":         _src,
        "status":         _raw_status if _raw_status in ("ready", "conflict_pending") else "ready",
        "timestamp":      datetime.utcnow().isoformat(),
        "spike_anticipation": _anticipation_applied,
        "anticipation_distance_pips": _anticipation_distance,
    }
    # Dès qu'un ordre pipeline est posté → activer cooldown GOM auto-trade immédiatement
    if _src == "pipeline":
        import time as _time
        _PIPELINE_LAST_EXEC[sym] = _time.time()
        logger.info(f"[PendingOrder] {sym} pipeline posté → cooldown GOM {PIPELINE_GOM_COOLDOWN_SEC}s activé")
    logger.info(f"[PendingOrder] Stocke : {sym} {direction} conf={final_conf:.2f} gom={gom_check['gom_action']}")
    logger.info(f"[PendingOrder] BEFORE RETURN: _anticipation_applied={_anticipation_applied}, _anticipation_distance={_anticipation_distance}")

    _response = {
        "ok": True,
        "symbol": sym,
        "order_id": sym,
        "gom_action": gom_check["gom_action"],
        "gom_warning": gom_check["gom_warning"],
        "confidence_adjusted": final_conf,
        "spike_anticipation_applied": _anticipation_applied,
        "anticipation_distance_pips": _anticipation_distance,
        "entry_price": _entry_price,
        "stop_loss": _stop_loss,
        "take_profit": _take_profit,
    }
    logger.info(f"[PendingOrder] RESPONSE KEYS: {list(_response.keys())} | TOTAL={len(_response)}")
    logger.info(f"[PendingOrder] RETURNING: spike_anticipation_applied={_response.get('spike_anticipation_applied')}")
    return _response


