class GomVerdictPayload(BaseModel):
    model_config = {"extra": "allow"}
    symbol: str
    verdict: str = "WAIT"   # BUY | SELL | WAIT | PERFECT BUY | ...
    score_buy: float = 0.0
    score_sell: float = 0.0
    spike_pct: float = 0.0
    # Indicateurs TradingView (envoyés par l'alerte Pine)
    vwap: Optional[float] = None
    bb_up: Optional[float] = None
    bb_mid: Optional[float] = None
    bb_dn: Optional[float] = None
    st_line: Optional[float] = None
    st_dir: Optional[int] = None     # 1=haussier, -1=baissier
    fib_0: Optional[float] = None
    fib_236: Optional[float] = None
    fib_382: Optional[float] = None
    fib_500: Optional[float] = None
    fib_618: Optional[float] = None
    fib_786: Optional[float] = None
    fib_100: Optional[float] = None
    rsi: Optional[float] = None
    price: Optional[float] = None
    verdict_num: Optional[int] = 0         # -3=PERFECT_SELL .. +3=PERFECT_BUY, 0=WAIT
    rsi_oversold: Optional[bool] = False   # RSI < 28 — rebond imminent sur position SELL
    rsi_overbought: Optional[bool] = False # RSI > 72 — retournement imminent sur position BUY
    verdict_gap: Optional[float] = None    # écart abs(score_sell - score_buy)
    entry_quality: Optional[float] = None  # % qualité d'entrée (0-100)
    coherence_pct: Optional[float] = None  # % cohérence du signal (0-100)
    filter_ratio: Optional[float] = None  # ratio confirmateurs alignés / 6 (0-1)
    kola_buy: Optional[float] = None
    kola_sell: Optional[float] = None
    kola_state: Optional[str] = None       # NEAR BUY | NEAR SELL | ---
    # MTF (même logique que tableau Pine)
    tf_m1_dir: Optional[str] = None
    tf_m1_rsi: Optional[int] = None
    tf_m5_dir: Optional[str] = None
    tf_m5_rsi: Optional[int] = None
    tf_m15_dir: Optional[str] = None
    tf_m15_rsi: Optional[int] = None
    tf_h1_dir: Optional[str] = None
    tf_h1_rsi: Optional[int] = None
    tf_h4_dir: Optional[str] = None
    tf_h4_rsi: Optional[int] = None
    tf_d1_dir: Optional[str] = None
    tf_d1_rsi: Optional[int] = None
    tf_w1_dir: Optional[str] = None
    tf_w1_rsi: Optional[int] = None
    tf_global_dir: Optional[str] = None
    tf_global_strength: Optional[int] = None
    # Chemin prédictif 200 bougies (Pine GOM_KOLA_SIDO)
    pred_path: Optional[str] = None
    pred_horizon: Optional[int] = 200
    pred_bull: Optional[int] = None
    pred_bear: Optional[int] = None
    pred_neut: Optional[int] = None
    pred_net: Optional[int] = None
    path_guided: Optional[bool] = None
    # Prédictions Bollinger Bands (300 bougies) — array de floats
    pred_bb_mid: Optional[list] = None
    pred_bb_up: Optional[list] = None
    pred_bb_dn: Optional[list] = None
    # Tableau SETUP TradingView (ordre limite MT5)
    setup_dir: Optional[int] = None
    setup_entry: Optional[float] = None
    setup_sl: Optional[float] = None
    setup_tp1: Optional[float] = None
    setup_tp2: Optional[float] = None
    setup_rr: Optional[float] = None
    setup_type: Optional[str] = None
    setup_confirm: Optional[str] = None
    # GHOST OrderFlow — envoyés par gom_verdict_poller quand l'indicateur est visible
    ghost_delta:   Optional[float] = None
    ghost_cvd:     Optional[float] = None
    ghost_buypct:  Optional[float] = None
    ghost_compass: Optional[float] = None
    ob_bull_top:   Optional[float] = None
    ob_bull_bot:   Optional[float] = None
    ob_bear_top:   Optional[float] = None
    ob_bear_bot:   Optional[float] = None
    spike_level: Optional[int] = None
    imminence_pct: Optional[float] = None
    spike_tradable: Optional[bool] = None
    pre_spike_pct: Optional[float] = None
    spike_progress_pct: Optional[float] = None
    bars_since_spike: Optional[int] = None
    spike_freq_bars: Optional[int] = None
    source: Optional[str] = None


def _dir_num_to_label(d: int) -> str:
    if d == 1:
        return "BULL"
    if d == -1:
        return "BEAR"
    return "NEUT"


def _gom_verdict_label_from_num(vnum: int) -> str:
    """Libellé verdict aligné sur GOM_KOLA_script.pine / GOMLPineCalculator."""
    n = int(vnum)
    if n >= 3:
        return "PERFECT BUY"
    if n == 2:
        return "GOOD BUY"
    if n == 1:
        return "BUY"
    if n <= -3:
        return "PERFECT SELL"
    if n == -2:
        return "GOOD SELL"
    if n == -1:
        return "SELL"
    return "WAIT"


def _gom_trust_precalculated_verdict(payload_source: str, payload: "GomVerdictPayload") -> bool:
    """Verdict déjà calculé par GOMLPineCalculator ou poller MT5 — ne pas écraser."""
    src = (payload_source or "").lower()
    trusted = (
        "live_calculation", "mt5_live", "mt5_upload", "mt5_direct",
        "tradingview", "tv", "tradingview_sync", "tradingview_fallback", "sync",
    )
    return payload.verdict_num is not None and any(t in src for t in trusted)


def _gom_apply_pine_verdict(record: dict) -> dict:
    """Recalcule verdict via GOMLPineCalculator (même logique que /gom-kola-dashboard)."""
    if GOM_LIVE_CALCULATOR_AVAILABLE and _gom_live_calc and getattr(_gom_live_calc, "pine", None):
        enriched = _gom_live_calc.pine.enrich_record(dict(record))
        record.update({
            "score_buy": enriched["score_buy"],
            "score_sell": enriched["score_sell"],
            "verdict_num": enriched["verdict_num"],
            "verdict": enriched["verdict"],
            "verdict_gap": enriched["verdict_gap"],
            "filter_ratio": enriched["filter_ratio"],
            "coherence_pct": enriched["coherence_pct"],
            "coherence_ok": enriched.get("coherence_ok", False),
            "entry_quality": round(float(enriched.get("entry_quality", 0)) * 100.0, 1),
            "data_source": record.get("data_source") or "live_calculation",
        })
        return record
    return record


def _parse_gom_tv_csv(text: str) -> Optional[dict]:
    """
    Parse l'alerte CSV Pine GOM_KOLA_SIDO (14 champs legacy ou 33 champs complets).
    Format: symbol,verdict,verdict_num,score_buy,score_sell,spike,rsi,os,ob,st_dir,quality,coherence,kola_buy,kola_sell[,gap,price,kola_state,d1,r1,...]
    """
    raw = text.strip()
    if not raw or raw.startswith("<"):
        return None
    if raw.startswith("{"):
        try:
            return json.loads(raw)
        except json.JSONDecodeError:
            return None
    parts = [p.strip() for p in raw.split(",")]
    if len(parts) < 14:
        return None

    def _bool(s: str) -> bool:
        return s.lower() in ("true", "1", "yes")

    def _flt(s: str, default: float = 0.0) -> float:
        try:
            return float(s.replace(" ", ""))
        except ValueError:
            return default

    def _int(s: str, default: int = 0) -> int:
        try:
            return int(round(float(s.replace(" ", ""))))
        except ValueError:
            return default

    symbol = parts[0]
    verdict_txt = parts[1]
    verdict_num = _int(parts[2])
    score_buy = _flt(parts[3])
    score_sell = _flt(parts[4])
    spike_pct = _flt(parts[5])
    rsi = _int(parts[6], 50)
    rsi_oversold = _bool(parts[7])
    rsi_overbought = _bool(parts[8])
    st_dir = _int(parts[9], 0)
    entry_quality = _flt(parts[10])
    coherence_pct = _flt(parts[11])
    kola_buy = _flt(parts[12])
    kola_sell = _flt(parts[13])

    verdict_gap = _flt(parts[14]) if len(parts) > 14 else abs(score_sell - score_buy)
    price = _flt(parts[15]) if len(parts) > 15 else None
    kola_state = parts[16] if len(parts) > 16 else "---"
    if kola_state == "NB":
        kola_state = "NEAR BUY"
    elif kola_state == "NS":
        kola_state = "NEAR SELL"

    out = {
        "symbol": symbol,
        "verdict": verdict_txt,
        "verdict_num": verdict_num,
        "score_buy": score_buy,
        "score_sell": score_sell,
        "spike_pct": spike_pct,
        "rsi": rsi,
        "rsi_oversold": rsi_oversold,
        "rsi_overbought": rsi_overbought,
        "st_dir": st_dir,
        "entry_quality": entry_quality,
        "coherence_pct": coherence_pct,
        "kola_buy": kola_buy,
        "kola_sell": kola_sell,
        "verdict_gap": verdict_gap,
        "price": price,
        "kola_state": kola_state,
    }

    if len(parts) >= 34:
        tf_keys = [
            ("m1", 17, 18), ("m5", 19, 20), ("m15", 21, 22),
            ("h1", 23, 24), ("h4", 25, 26), ("d1", 27, 28), ("w1", 29, 30),
        ]
        for lk, di, ri in tf_keys:
            d = _int(parts[di])
            out[f"tf_{lk}_dir"] = _dir_num_to_label(d)
            out[f"tf_{lk}_rsi"] = _int(parts[ri])
        gd = _int(parts[31])
        tb = _int(parts[32])
        ts = _int(parts[33])
        out["tf_global_dir"] = _dir_num_to_label(gd)
        out["tf_global_strength"] = max(tb, ts)

    if len(parts) > 36:
        out["pred_bull"] = _int(parts[34])
        out["pred_bear"] = _int(parts[35])
        out["pred_neut"] = _int(parts[36])
    if len(parts) > 37 and parts[37]:
        path_raw = parts[37].strip().upper()
        if len(path_raw) >= 20 and all(c in "UDN" for c in path_raw):
            out["pred_path"] = path_raw[:200]
            out["pred_horizon"] = len(out["pred_path"])

    if len(parts) > 43:
        out["setup_dir"] = _int(parts[38])
        out["setup_entry"] = _flt(parts[39])
        out["setup_sl"] = _flt(parts[40])
        out["setup_tp1"] = _flt(parts[41])
        out["setup_tp2"] = _flt(parts[42])
        out["setup_rr"] = _flt(parts[43])
        if out.get("setup_dir") == 1:
            out["setup_type"] = "OB_BULL"
        elif out.get("setup_dir") == -1:
            out["setup_type"] = "OB_BEAR"

    if len(parts) > 48:
        out["spike_level"] = _int(parts[44])
        out["spike_pred_prob"] = _int(parts[45])
        out["imminence_pct"] = _flt(parts[46])
        spike_trad = _int(parts[48]) == 1
        out["spike_tradable"] = spike_trad
        bc_dir = _int(parts[49]) if len(parts) > 49 else 0
        if spike_trad:
            if bc_dir == 1 or out.get("setup_dir") == 1:
                out["setup_type"] = "SPIKE_BOOM"
                out["verdict"] = "GOOD BUY"
                out["verdict_num"] = 2
            elif bc_dir == -1 or out.get("setup_dir") == -1:
                out["setup_type"] = "SPIKE_CRASH"
                out["verdict"] = "GOOD SELL"
                out["verdict_num"] = -2

    return out


def _estimate_atr_from_record(record: dict) -> float:
    price = float(record.get("price") or 0)
    if price <= 0:
        return 1.0
    sym = (record.get("symbol") or "").upper()
    if "XAU" in sym or "GOLD" in sym:
        return price * 0.0012
    if "BOOM" in sym or "CRASH" in sym:
        return price * 0.008
    return price * 0.0008


def _persist_gom_path_prediction_rds(sym: str, record: dict) -> Optional[str]:
    if not AWS_RDS_AVAILABLE or not record.get("pred_path"):
        return None
    try:
        price = float(record.get("price") or 0)
        if price <= 0:
            return None
        meta = {
            "verdict": record.get("verdict"),
            "verdict_num": record.get("verdict_num"),
            "pred_bull": record.get("pred_bull"),
            "pred_bear": record.get("pred_bear"),
            "pred_net": record.get("pred_net"),
            "path_guided": record.get("path_guided"),
            "source": record.get("source", "gom_kola"),
        }
        return aws_rds_client.insert_gom_path_prediction_run(
            sym,
            "M1",
            str(record["pred_path"]),
            price,
            _estimate_atr_from_record(record),
            metadata=meta,
        )
    except Exception as e:
        logger.warning(f"[GomPath] RDS store skipped for {sym}: {e}")
        return None


def _normalize_tf_dir_label(val: Any) -> str:
    """Convertit -1/0/1 ou BUY/SELL en BULL/BEAR/NEUT pour le dashboard MT5."""
    if val is None or val == "":
        return ""
    if isinstance(val, str):
        s = val.strip().upper()
        if s in ("BULL", "BEAR", "NEUT", "NEUTRAL"):
            return "NEUT" if s == "NEUTRAL" else s
        if s in ("BUY", "LONG"):
            return "BULL"
        if s in ("SELL", "SHORT"):
            return "BEAR"
        try:
            val = int(float(s.replace(",", ".")))
        except ValueError:
            return s
    try:
        return _dir_num_to_label(int(val))
    except (TypeError, ValueError):
        return str(val)


def _lookup_gom_store(sym: str, store: dict) -> Optional[dict]:
    """Recherche souple (Boom500Index vs BOOM 500 INDEX)."""
    if not sym:
        return None
    if sym in store:
        return store[sym]
    sym_clean = sym.upper().replace(" ", "").replace("INDEX", "")
    for key, val in store.items():
        k_clean = str(key).upper().replace(" ", "").replace("INDEX", "")
        if k_clean == sym_clean:
            return val
    return None


def _normalize_gom_record_dirs(record: dict) -> None:
    for lk in ("m1", "m5", "m15", "h1", "h4", "d1", "w1", "global"):
        dk = f"tf_{lk}_dir"
        if dk in record:
            record[dk] = _normalize_tf_dir_label(record.get(dk))


def _gom_mtf_cache_key(mt5_symbol: str) -> str:
    return str(mt5_symbol or "").upper().replace(" ", "").replace("INDEX", "")


def _tf_dir_value_missing(val: Any) -> bool:
    if val in (None, "", 0, "0"):
        return True
    lbl = _normalize_tf_dir_label(val)
    return lbl == "NEUT" and val in (None, "", 0, "0", "NEUT", "NEUTRAL")


def _fetch_gom_mtf_snapshot(mt5_symbol: str) -> dict:
    """Snapshot M1..D1 via copy_rates léger (évite get_mt5_indicators complet)."""
    out: dict = {}
    if not mt5_symbol:
        return out
    try:
        import MetaTrader5 as mt5
    except ImportError:
        return out
    if not mt5.initialize():
        return out

    sym = mt5_symbol
    if mt5.symbol_info(sym) is None:
        try:
            from symbol_mapper import resolve_mt5_symbol
            sym = resolve_mt5_symbol(mt5_symbol) or mt5_symbol
        except Exception:
            sym = mt5_symbol

    tf_map = {
        "m1": mt5.TIMEFRAME_M1, "m5": mt5.TIMEFRAME_M5, "m15": mt5.TIMEFRAME_M15,
        "h1": mt5.TIMEFRAME_H1, "h4": mt5.TIMEFRAME_H4, "d1": mt5.TIMEFRAME_D1,
    }

    def _ema_last(closes: list, period: int):
        if len(closes) < period:
            return None
        mult = 2.0 / (period + 1)
        ema = sum(closes[:period]) / period
        for price in closes[period:]:
            ema = (price - ema) * mult + ema
        return ema

    def _rsi_last(closes: list, period: int = 14):
        if len(closes) < period + 1:
            return None
        gains, losses = [], []
        for i in range(1, len(closes)):
            delta = closes[i] - closes[i - 1]
            gains.append(max(delta, 0.0))
            losses.append(max(-delta, 0.0))
        avg_g = sum(gains[-period:]) / period
        avg_l = sum(losses[-period:]) / period
        if avg_l == 0:
            return 100
        rs = avg_g / avg_l
        return int(round(100 - 100 / (1 + rs)))

    for lk, mt5_tf in tf_map.items():
        rates = mt5.copy_rates_from_pos(sym, mt5_tf, 0, 80)
        if rates is None or len(rates) == 0:
            continue
        closes = [float(r[4]) for r in rates]
        e20 = _ema_last(closes, 20)
        e50 = _ema_last(closes, 50)
        direction = 0
        if e20 is not None and e50 is not None:
            if e20 > e50 * 1.00005:
                direction = 1
            elif e20 < e50 * 0.99995:
                direction = -1
        out[f"tf_{lk}_dir"] = _dir_num_to_label(direction)
        rsi = _rsi_last(closes)
        if rsi is not None:
            out[f"tf_{lk}_rsi"] = rsi
    return out


def _get_gom_mtf_snapshot(mt5_symbol: str, force_refresh: bool = False) -> dict:
    key = _gom_mtf_cache_key(mt5_symbol)
    now = datetime.utcnow()
    cached = _GOM_MTF_CACHE.get(key)
    if not force_refresh and cached:
        age = (now - cached["ts"]).total_seconds()
        if age < _GOM_MTF_CACHE_TTL_SEC:
            return dict(cached["fields"])
    fields = _fetch_gom_mtf_snapshot(mt5_symbol)
    if fields:
        _GOM_MTF_CACHE[key] = {"ts": now, "fields": fields}
        return dict(fields)
    if cached:
        return dict(cached["fields"])
    return {}


def _apply_gom_mtf_snapshot(record: dict, mt5_symbol: str, fetch: bool = False) -> None:
    if not mt5_symbol:
        return
    snapshot = _get_gom_mtf_snapshot(mt5_symbol, force_refresh=fetch)
    for lk in ("m1", "m5", "m15", "h1", "h4", "d1"):
        dir_key = f"tf_{lk}_dir"
        rsi_key = f"tf_{lk}_rsi"
        if _tf_dir_value_missing(record.get(dir_key)):
            if snapshot.get(dir_key):
                record[dir_key] = snapshot[dir_key]
            else:
                record[dir_key] = _normalize_tf_dir_label(record.get(dir_key)) or "NEUT"
        else:
            record[dir_key] = _normalize_tf_dir_label(record.get(dir_key))
        if record.get(rsi_key) in (None, "", 0) and snapshot.get(rsi_key):
            record[rsi_key] = snapshot[rsi_key]
    gd = _normalize_tf_dir_label(record.get("tf_global_dir"))
    if gd:
        record["tf_global_dir"] = gd


def _enrich_gom_mtf_from_mt5(record: dict, mt5_symbol: str, fetch: bool = True) -> None:
    """Complète M1..D1 depuis MT5 si Pine n'exporte que tf_global (comme TradeManager)."""
    _apply_gom_mtf_snapshot(record, mt5_symbol, fetch=fetch)
    _normalize_gom_record_dirs(record)


def _build_gom_mt5_payload(record: dict) -> dict:
    """Payload plat pour SMC_Universal / TradeManager (dashboard GOM)."""
    out = dict(record)

    # Calculer les tendances multi-TF si pas présentes
    def infer_tf_dir(bb_mid: float, current_price: float, rsi: int) -> str:
        """Infère la tendance depuis Bollinger Mid + RSI."""
        if bb_mid <= 0:
            return "NEUT"
        if current_price > bb_mid and rsi > 50:
            return "BULL"
        if current_price < bb_mid and rsi < 50:
            return "BEAR"
        return "NEUT"

    # M1, M5, M15, H1, H4, D1 (utiliser RSI + BB disponibles)
    current_price = record.get("entry", record.get("bb_mid", 0))
    for lk, tf_name in [("m1", "M1"), ("m5", "M5"), ("m15", "M15"), ("h1", "H1"), ("h4", "H4"), ("d1", "D1")]:
        dk = f"tf_{lk}_dir"
        if dk not in out or out[dk] == "NEUT" or out[dk] == 0 or out[dk] == "":
            # Infère depuis RSI + BB Mid
            rsi_val = record.get(f"tf_{lk}_rsi", 50)
            bb_mid = record.get("bb_mid", 0)
            inferred = infer_tf_dir(bb_mid, current_price, int(rsi_val) if rsi_val else 50)
            out[dk] = inferred if inferred else "NEUT"

        if lk != "global":
            rk = f"tf_{lk}_rsi"
            if rk not in out:
                out[rk] = record.get(rk, 50)

    # Global trend (composé de tous les TF)
    if "tf_global_dir" not in out or out["tf_global_dir"] == "NEUT":
        bull_count = sum(1 for lk in ("m1", "m5", "m15", "h1", "h4", "d1")
                         if out.get(f"tf_{lk}_dir") == "BULL")
        bear_count = sum(1 for lk in ("m1", "m5", "m15", "h1", "h4", "d1")
                         if out.get(f"tf_{lk}_dir") == "BEAR")
        if bull_count >= 3:
            out["tf_global_dir"] = "BULL"
        elif bear_count >= 3:
            out["tf_global_dir"] = "BEAR"
        else:
            out["tf_global_dir"] = "NEUT"

    if "tf_global_strength" not in out:
        out["tf_global_strength"] = record.get("tf_global_strength", 0)

    _normalize_gom_record_dirs(out)
    for key in (
        "setup_dir", "setup_entry", "setup_sl", "setup_tp1", "setup_tp2", "setup_rr",
        "setup_type", "setup_confirm", "setup_valid",
        "ghost_delta", "ghost_cvd", "ghost_buypct", "ghost_compass",
        "ob_bull_top", "ob_bull_bot", "ob_bear_top", "ob_bear_bot",
        "pred_path", "pred_net", "pred_bull", "pred_bear", "pred_neut",
        "path_guided", "kola_state", "data_source",
        "pred_bb_mid", "pred_bb_up", "pred_bb_dn",
        "spike_level", "imminence_pct", "spike_tradable", "pre_spike_pct",
        "spike_progress_pct", "bars_since_spike", "spike_freq_bars",
    ):
        if key not in out:
            out[key] = record.get(key)
    if out.get("verdict"):
        out["verdict"] = str(out["verdict"]).upper()

    # Forcer les prédictions BB si elles existent dans le record
    if "pred_bb_mid" in record:
        out["pred_bb_mid"] = record["pred_bb_mid"]
    if "pred_bb_up" in record:
        out["pred_bb_up"] = record["pred_bb_up"]
    if "pred_bb_dn" in record:
        out["pred_bb_dn"] = record["pred_bb_dn"]

    sym = record.get("symbol") or out.get("symbol")
    if sym:
        _enrich_bc_volatility(out, str(sym))
        _enrich_cognition_forecast(out, str(sym), str(record.get("chart_tf") or "M1"))
        out["entry_probability"] = round(_compute_entry_probability(out), 1)

    return out


def _gom_verdict_record_from_payload(payload: GomVerdictPayload, enrich_mt5: bool = True) -> tuple:
    """Construit l'entrée _GOM_VERDICT_STORE depuis un payload validé."""
    extra = payload.model_dump(exclude_none=True)
    sym = _resolve_symbol(payload.symbol)

    # Fonction helper pour obtenir une valeur avec défaut
    def get_or(val, default=0.0):
        return val if val is not None else default

    record = {
        "verdict": (payload.verdict or "WAIT").upper(),
        "score_buy": get_or(payload.score_buy, 0.0),
        "score_sell": get_or(payload.score_sell, 0.0),
        "spike_pct": get_or(payload.spike_pct, 0.0),
        "vwap": get_or(payload.vwap, 0.0),
        "bb_up": get_or(payload.bb_up, 0.0),
        "bb_mid": get_or(payload.bb_mid, 0.0),
        "bb_dn": get_or(payload.bb_dn, 0.0),
        "st_line": get_or(payload.st_line, 0.0),
        "st_dir": get_or(payload.st_dir, 0),
        "fib_0": get_or(payload.fib_0, 0.0),
        "fib_236": get_or(payload.fib_236, 0.0),
        "fib_382": get_or(payload.fib_382, 0.0),
        "fib_500": get_or(payload.fib_500, 0.0),
        "fib_618": get_or(payload.fib_618, 0.0),
        "fib_786": get_or(payload.fib_786, 0.0),
        "fib_100": get_or(payload.fib_100, 0.0),
        "rsi": get_or(payload.rsi, 50),
        "price": get_or(payload.price, 0.0),
        "verdict_num": payload.verdict_num or 0,  # Will be recalculated below
        "rsi_oversold": payload.rsi_oversold or False,
        "rsi_overbought": payload.rsi_overbought or False,
        "verdict_gap": get_or(payload.verdict_gap, 0.0),
        "entry_quality": get_or(payload.entry_quality, 0.0),
        "coherence_pct": get_or(payload.coherence_pct, 0.0),
        "filter_ratio": get_or(payload.filter_ratio, 0.0),
        "entry": get_or(payload.price, 0.0),   # prix courant → entry pour pipelines
        "close": get_or(payload.price, 0.0),
        "source": str(extra.get("source") or getattr(payload, "source", None) or "api"),
        "kola_buy": get_or(payload.kola_buy, 0.0),
        "kola_sell": get_or(payload.kola_sell, 0.0),
        "kola_state": payload.kola_state or "---",
        "timestamp": datetime.utcnow().isoformat(),
        # SL/TP/ATR — calculés par le poller MT5 (ATR-based), absents si source TV
        "sl": float(extra.get("sl") or 0.0),
        "tp": float(extra.get("tp") or 0.0),
        "atr": float(extra.get("atr") or extra.get("atr14") or 0.0),
        "atr14": float(extra.get("atr14") or extra.get("atr") or 0.0),
        # Timeframe directions (pour IA Status v2 multi-TF)
        "tf_m1_dir": str(payload.tf_m1_dir or "NEUT"),
        "tf_m1_rsi": int(payload.tf_m1_rsi or 50),
        "tf_m5_dir": str(payload.tf_m5_dir or "NEUT"),
        "tf_m5_rsi": int(payload.tf_m5_rsi or 50),
        "tf_m15_dir": str(payload.tf_m15_dir or "NEUT"),
        "tf_m15_rsi": int(payload.tf_m15_rsi or 50),
        "tf_m30_dir": str(getattr(payload, "tf_m30_dir", None) or "NEUT"),
        "tf_m30_rsi": int(getattr(payload, "tf_m30_rsi", None) or 50),
        "tf_h1_dir": str(payload.tf_h1_dir or "NEUT"),
        "tf_h1_rsi": int(payload.tf_h1_rsi or 50),
        "tf_h4_dir": str(payload.tf_h4_dir or "NEUT"),
        "tf_h4_rsi": int(payload.tf_h4_rsi or 50),
        "tf_d1_dir": str(payload.tf_d1_dir or "NEUT"),
        "tf_d1_rsi": int(payload.tf_d1_rsi or 50),
        "tf_w1_dir": str(payload.tf_w1_dir or "NEUT"),
        "tf_global_dir": str(payload.tf_global_dir or "NEUT"),
        "tf_global_strength": int(payload.tf_global_strength or 0),
    }

    # ══════════════════════════════════════════════════════════════
    # VERDICT — MT5 live calc ou Pine poller = source de vérité
    # Sinon recalcul via GOMLPineCalculator (pas de seuils simplifiés)
    # ══════════════════════════════════════════════════════════════

    score_buy = float(record.get("score_buy") or 0)
    score_sell = float(record.get("score_sell") or 0)
    coherence_pct = float(record.get("coherence_pct") or 0)
    filter_ratio = float(record.get("filter_ratio") or 0)
    gap = abs(score_buy - score_sell)
    payload_source = str(record.get("source") or "").lower()

    logger.info(f"[GOM VERDICT] {_resolve_symbol(payload.symbol)} src={payload_source}")

    if _gom_trust_precalculated_verdict(payload_source, payload):
        vnum = int(payload.verdict_num)
        record["verdict_num"] = vnum
        record["verdict"] = (
            str(payload.verdict).upper()
            if payload.verdict
            else _gom_verdict_label_from_num(vnum)
        )
        record["verdict_gap"] = float(payload.verdict_gap if payload.verdict_gap is not None else gap)
        record["filter_ratio"] = filter_ratio
        record["coherence_pct"] = coherence_pct
        if "live" in payload_source or "mt5" in payload_source:
            record["data_source"] = payload_source if payload_source else "live_calculation"
        logger.info(f"  → trust vn={vnum} {record['verdict']}")
    else:
        _gom_apply_pine_verdict(record)
        logger.info(
            f"  → pine recalc vn={record.get('verdict_num')} "
            f"{record.get('verdict')} gap={record.get('verdict_gap')}"
        )

    # Ajouter les champs optionnels avec défauts pour éviter les null
    optional_fields = {
        "tf_m1_dir": 0, "tf_m1_rsi": 50, "tf_m5_dir": 0, "tf_m5_rsi": 50,
        "tf_m15_dir": 0, "tf_m15_rsi": 50, "tf_h1_dir": 0, "tf_h1_rsi": 50,
        "tf_h4_dir": 0, "tf_h4_rsi": 50, "tf_d1_dir": 0, "tf_d1_rsi": 50,
        "tf_w1_dir": 0, "tf_w1_rsi": 50,
        "tf_global_dir": "NEUTRAL", "tf_global_strength": 0,
        "pred_path": "", "pred_horizon": 200,
        "pred_bull": 0, "pred_bear": 0, "pred_neut": 0, "pred_net": 0,
        "path_guided": "", "setup_inferred": False,
        "pred_bb_mid": [], "pred_bb_up": [], "pred_bb_dn": [],
        "setup_buy_prob": 0.0, "setup_sell_prob": 0.0, "setup_valid_prob": 0.0,
        "pred_direction_hit_rate": 0.0, "setup_score_live": 0.0, "samples": 0,
        "ghost_delta": 0.0, "ghost_cvd": 0.0, "ghost_buypct": 0.0, "ghost_compass": 0.0,
        "ob_bull_top": 0.0, "ob_bull_bot": 0.0, "ob_bear_top": 0.0, "ob_bear_bot": 0.0,
    }
    for key, default in optional_fields.items():
        record[key] = extra.get(key) if extra.get(key) is not None else default

    record["setup_dir"] = int(extra.get("setup_dir") or payload.setup_dir or 0)
    record["setup_entry"] = float(extra.get("setup_entry") or payload.setup_entry or 0)
    record["setup_sl"] = float(extra.get("setup_sl") or payload.setup_sl or 0)
    record["setup_tp1"] = float(extra.get("setup_tp1") or payload.setup_tp1 or 0)
    record["setup_tp2"] = float(extra.get("setup_tp2") or payload.setup_tp2 or 0)
    record["setup_rr"] = float(extra.get("setup_rr") or payload.setup_rr or 0)
    record["setup_type"] = str(extra.get("setup_type") or payload.setup_type or "")
    record["setup_confirm"] = str(extra.get("setup_confirm") or payload.setup_confirm or "")
    record["ob_bull_top"] = float(extra.get("ob_bull_top") or payload.ob_bull_top or 0)
    record["ob_bull_bot"] = float(extra.get("ob_bull_bot") or payload.ob_bull_bot or 0)
    record["ob_bear_top"] = float(extra.get("ob_bear_top") or payload.ob_bear_top or 0)
    record["ob_bear_bot"] = float(extra.get("ob_bear_bot") or payload.ob_bear_bot or 0)
    if extra.get("spike_level") is not None or payload.spike_level is not None:
        record["spike_level"] = int(extra.get("spike_level") or payload.spike_level or 0)
    if extra.get("imminence_pct") is not None or payload.imminence_pct is not None:
        record["imminence_pct"] = float(extra.get("imminence_pct") or payload.imminence_pct or 0)
    if extra.get("spike_tradable") is not None or payload.spike_tradable is not None:
        record["spike_tradable"] = bool(extra.get("spike_tradable") if extra.get("spike_tradable") is not None else payload.spike_tradable)
    if extra.get("pre_spike_pct") is not None or payload.pre_spike_pct is not None:
        record["pre_spike_pct"] = float(extra.get("pre_spike_pct") or payload.pre_spike_pct or 0)
    if extra.get("spike_progress_pct") is not None or payload.spike_progress_pct is not None:
        record["spike_progress_pct"] = float(extra.get("spike_progress_pct") or payload.spike_progress_pct or 0)
    if extra.get("bars_since_spike") is not None or payload.bars_since_spike is not None:
        record["bars_since_spike"] = int(extra.get("bars_since_spike") or payload.bars_since_spike or 0)
    if extra.get("spike_freq_bars") is not None or payload.spike_freq_bars is not None:
        record["spike_freq_bars"] = int(extra.get("spike_freq_bars") or payload.spike_freq_bars or 0)
    record["setup_valid"] = (
        record["setup_dir"] != 0
        and record["setup_entry"] > 0
        and record["setup_sl"] > 0
        and record["setup_tp1"] > 0
    )

    # Ajouter les prédictions Bollinger Bands
    record["pred_bb_mid"] = payload.pred_bb_mid or []
    record["pred_bb_up"] = payload.pred_bb_up or []
    record["pred_bb_dn"] = payload.pred_bb_dn or []

    if GOM_PATH_AVAILABLE and infer_tv_setup_from_gom:
        try:
            record = infer_tv_setup_from_gom(record)
            record["setup_valid"] = (
                int(record.get("setup_dir") or 0) != 0
                and float(record.get("setup_entry") or 0) > 0
                and float(record.get("setup_sl") or 0) > 0
                and float(record.get("setup_tp1") or 0) > 0
            )
        except Exception as e:
            logger.warning(f"[GomSetup] infer_tv_setup: {e}")

    if GOM_PATH_AVAILABLE and apply_path_to_gom_record:
        try:
            record = apply_path_to_gom_record(record, record.get("pred_path"))
        except Exception as e:
            logger.warning(f"[GomPath] apply_path_to_gom_record: {e}")

    _enrich_gom_record_reliability(sym, record)

    _normalize_gom_record_dirs(record)
    try:
        from symbol_mapper import resolve_mt5_symbol
        _apply_gom_mtf_snapshot(record, resolve_mt5_symbol(payload.symbol), fetch=enrich_mt5)
    except Exception as e:
        logger.debug(f"[GomMTF] enrich skip {sym}: {e}")
    record["data_source"] = str(extra.get("source") or "TV")

    # DEBUG: Verify predictions are in record
    if record.get("pred_bb_mid"):
        logger.info(f"[GOM-Pred-Store] {sym}: storing {len(record.get('pred_bb_mid', []))} pred_bb_mid points")

    return sym, record


def _enrich_gom_record_reliability(sym: str, record: dict) -> None:
    """Fusionne proba setup RDS (prediction_outcomes) dans le verdict GOM."""
    if not AWS_RDS_AVAILABLE:
        return
    try:
        rel = aws_rds_client.get_gom_setup_reliability(sym, "M1", lookback_days=14)
        for key in (
            "pred_direction_hit_rate",
            "setup_buy_prob",
            "setup_sell_prob",
            "setup_valid_prob",
            "setup_score_live",
            "samples",
        ):
            val = rel.get(key)
            if val is not None:
                record[key] = val
        # Prioriser RDS si plus de samples que le calcul live
        if int(rel.get("samples") or 0) >= 20:
            if rel.get("setup_buy_prob") is not None:
                record["setup_buy_prob"] = rel["setup_buy_prob"]
            if rel.get("setup_sell_prob") is not None:
                record["setup_sell_prob"] = rel["setup_sell_prob"]
            if rel.get("setup_valid_prob") is not None:
                record["setup_valid_prob"] = rel["setup_valid_prob"]
    except Exception as e:
        logger.warning(f"[GomReliability] {sym}: {e}")


def _sync_gom_tableau_from_verdict(sym: str, record: dict) -> None:
    """Met à jour _GOM_TABLEAU_STORE pour /gom-tableau-complete (format nested)."""
    tf_map = {}
    for label in ("M1", "M5", "M15", "H1", "H4", "D1", "W1"):
        lk = label.lower()
        direction = record.get(f"tf_{lk}_dir")
        if direction:
            tf_map[label] = {
                "direction": _normalize_tf_dir_label(direction),
                "rsi": record.get(f"tf_{lk}_rsi", 0),
            }
    if record.get("tf_global_dir"):
        tf_map["GLOBAL"] = {
            "direction": _normalize_tf_dir_label(record.get("tf_global_dir")),
            "strength": record.get("tf_global_strength", 0),
        }
    if not tf_map and not record.get("verdict"):
        return
    _GOM_TABLEAU_STORE[sym] = {
        "timeframes": tf_map,
        "verdict": {
            "verdict": record.get("verdict", "WAIT"),
            "kola_state": record.get("kola_state", "---"),
            "score_buy": record.get("score_buy"),
            "score_sell": record.get("score_sell"),
        },
        "timestamp": record.get("timestamp", datetime.utcnow().isoformat()),
    }


def _maybe_promote_gom_to_pending_order(sym: str, record: dict) -> None:
    """
    Quand TV envoie GOOD/PERFECT, crée un pending-order market pour TradeManager.
    Évite le trou : gom-verdict OK mais ok=false sur /pending-order.
    """
    if os.getenv("GOM_AUTO_PENDING_ORDER", "true").lower() not in ("1", "true", "yes"):
        return

    vnum = int(record.get("verdict_num") or 0)
    buy = float(record.get("score_buy") or 0)
    sell = float(record.get("score_sell") or 0)
    gap_thr = float(os.getenv("GOM_STRONG_SCORE_GAP", "1.0"))

    # Exception for Boom/Crash: respect their native direction bias
    sym_lower = str(sym).lower().replace(" ", "")
    is_boom = "boom" in sym_lower
    is_crash = "crash" in sym_lower

    if vnum not in (2, 3, -2, -3):
        # Boom naturally biases BUY, Crash naturally biases SELL
        # If scores are inverted, swap them for verdict calculation
        if is_boom and sell > buy:
            buy, sell = sell, buy  # Swap for Boom to prioritize BUY
        elif is_crash and buy > sell:
            buy, sell = sell, buy  # Swap for Crash to prioritize SELL

        if sell - buy >= gap_thr:
            vnum = -2
            record = {**record, "verdict_num": vnum, "verdict": record.get("verdict") or "GOOD SELL"}
        elif buy - sell >= gap_thr:
            vnum = 2
            record = {**record, "verdict_num": vnum, "verdict": record.get("verdict") or "GOOD BUY"}
        else:
            return

    quality = float(record.get("entry_quality") or 0)
    coherence = float(record.get("coherence_pct") or 0)
    min_q = float(os.getenv("GOM_AUTO_MIN_QUALITY", "35"))
    # IA status gate : coherence_pct doit être >= 70% pour tout trade auto-promu
    min_c = float(os.getenv("GOM_AUTO_MIN_COHERENCE", "70"))
    if quality < min_q or (coherence > 0 and coherence < min_c):
        logger.info(f"[GomAutoTrade] {sym} — IA status gate: coherence={coherence:.0f}% < {min_c:.0f}% → skip")
        return

    # Gate MTF : H4+H1+M15 doivent confirmer la direction avant auto-promotion
    _direction = "BUY" if vnum > 0 else "SELL"
    _side     = "BULL" if _direction == "BUY" else "BEAR"
    _opposite = "BEAR" if _direction == "BUY" else "BULL"
    _h4  = str(record.get("tf_h4_dir") or "NEUT")
    _h1  = str(record.get("tf_h1_dir") or "NEUT")
    _m15 = str(record.get("tf_m15_dir") or "NEUT")
    _tfs_all = [
        str(record.get("tf_m1_dir")  or "NEUT"),
        str(record.get("tf_m5_dir")  or "NEUT"),
        _m15, _h1, _h4,
        str(record.get("tf_d1_dir")  or "NEUT"),
    ]
    _all_neut = all(d == "NEUT" for d in _tfs_all)
    if not _all_neut:
        # Rejet absolu : H4 ET H1 opposés
        if _h4 == _opposite and _h1 == _opposite:
            logger.info(f"[GomAutoTrade] {sym} — MTF rejet absolu H4={_h4} H1={_h1} contre {_direction} → skip")
            return
        # Structure : H4 confirme OU (H1 + M15 confirment)
        _struct_ok = (_h4 == _side) or (_h1 == _side and _m15 == _side)
        if not _struct_ok:
            logger.info(f"[GomAutoTrade] {sym} — MTF structure insuffisante H4={_h4} H1={_h1} M15={_m15} pour {_direction} → skip")
            return
        # Cohérence >= 4/6
        _count = sum(1 for d in _tfs_all if d == _side)
        if _count < 4:
            logger.info(f"[GomAutoTrade] {sym} — MTF cohérence {_count}/6 < 4 pour {_direction} → skip")
            return

    kola = (record.get("kola_state") or "---").upper()
    strong_gap = abs(sell - buy) >= gap_thr
    if not strong_gap:
        if vnum > 0 and "NEAR SELL" in kola:
            return
        if vnum < 0 and "NEAR BUY" in kola:
            return

    direction = "BUY" if vnum > 0 else "SELL"
    existing = _PENDING_ORDER_STORE.get(sym)

    # Ne pas écraser un ordre venant du pipeline (source != gom_tv_sync)
    # Le pipeline a la priorité : SL/TP calculés, execution_type correct
    if existing and existing.get("source") not in ("gom_tv_sync", "mt5_live", None, ""):
        logger.info(f"[GomAutoTrade] {sym} — ordre pipeline existant (source={existing.get('source')}) → GOM skip")
        return

    # Ne pas écraser un ordre executing — il est en cours d'exécution MT5, ne pas l'interrompre
    if existing and (existing.get("status") or "ready") == "executing":
        logger.info(f"[GomAutoTrade] {sym} — ordre en cours d'exécution (executing) → GOM skip")
        return

    # Cooldown post-pipeline : bloquer GOM auto-trade 2 min après exécution pipeline
    import time as _time
    last_pipe = _PIPELINE_LAST_EXEC.get(sym, 0)
    if _time.time() - last_pipe < PIPELINE_GOM_COOLDOWN_SEC:
        logger.info(f"[GomAutoTrade] {sym} — cooldown pipeline actif ({PIPELINE_GOM_COOLDOWN_SEC}s) → GOM skip")
        return

    if existing and (existing.get("status") or "ready") == "ready":
        ex_dir = (existing.get("action") or existing.get("recommendation") or "").upper()
        if ex_dir == direction and int(existing.get("gom_verdict_num") or 0) == vnum:
            return

    lot = float(os.getenv("GOM_AUTO_LOT", "0.01"))
    price = float(record.get("price") or record.get("entry") or 0)

    # Calculer SL/TP depuis ATR — refuser si price=0 ou ATR indisponible
    atr_val = float(record.get("atr") or record.get("atr14") or 0)
    if price <= 0:
        logger.warning(f"[GomAutoTrade] {sym} price=0 — ordre non créé (SL/TP impossible à calculer)")
        return
    if atr_val <= 0:
        # Fallback: 0.5% du prix comme distance ATR minimale
        atr_val = price * 0.005
        logger.info(f"[GomAutoTrade] {sym} ATR absent — fallback 0.5% du prix ({atr_val:.5f})")

    sl_dist = max(atr_val * 1.5, price * 0.002)  # minimum 0.2% du prix
    tp_dist = sl_dist * 2.0  # RR 1:2
    auto_sl = round(price - sl_dist if direction == "BUY" else price + sl_dist, 5)
    auto_tp = round(price + tp_dist if direction == "BUY" else price - tp_dist, 5)

    _PENDING_ORDER_STORE[sym] = {
        "symbol": sym,
        "action": direction,
        "recommendation": direction,
        "execution_type": "market",
        "entry_price": price,
        "stop_loss": auto_sl,
        "take_profit": auto_tp,
        "lot": lot,
        "confidence": 0.88,
        "gom_verdict": record.get("verdict"),
        "gom_verdict_num": vnum,
        "gom_score_buy": record.get("score_buy"),
        "gom_score_sell": record.get("score_sell"),
        "status": "ready",
        "timestamp": datetime.utcnow().isoformat(),
        "source": "gom_tv_sync",
    }
    logger.info(
        f"[GomAutoTrade] pending-order {sym} {direction} vnum={vnum} "
        f"Q={quality:.0f}% C={coherence:.0f}%"
    )


def _store_gom_verdict_payload_bg(payload: GomVerdictPayload) -> None:
    """Exécuté en background — enrichissement MTF + sync tableau sans bloquer le POST."""
    try:
        sym, record = _gom_verdict_record_from_payload(payload, enrich_mt5=True)
        run_id = _persist_gom_path_prediction_rds(sym, record)
        if run_id:
            record["prediction_run_id"] = run_id
        _GOM_VERDICT_STORE[sym] = record
        _sync_gom_tableau_from_verdict(sym, record)
        _maybe_promote_gom_to_pending_order(sym, record)
        logger.info(
            f"[GomVerdict] {sym} verdict={record['verdict']} num={record['verdict_num']} "
            f"buy={record['score_buy']:.1f} sell={record['score_sell']:.1f} "
            f"rsi={record.get('rsi')} quality={record.get('entry_quality')}% "
            f"coherence={record.get('coherence_pct')}% "
            f"path_net={record.get('pred_net')} run={run_id or '-'}"
        )
    except Exception as e:
        logger.error(f"[GomVerdict] background task error: {e}")


def _store_gom_verdict_payload(payload: GomVerdictPayload) -> dict:
    sym, record = _gom_verdict_record_from_payload(payload)
    run_id = _persist_gom_path_prediction_rds(sym, record)
    if run_id:
        record["prediction_run_id"] = run_id
    _GOM_VERDICT_STORE[sym] = record
    _sync_gom_tableau_from_verdict(sym, record)
    _maybe_promote_gom_to_pending_order(sym, record)
    logger.info(
        f"[GomVerdict] {sym} verdict={record['verdict']} num={record['verdict_num']} "
        f"buy={record['score_buy']:.1f} sell={record['score_sell']:.1f} "
        f"rsi={record.get('rsi')} quality={record.get('entry_quality')}% "
        f"coherence={record.get('coherence_pct')}% path_net={record.get('pred_net')}"
    )
    return {
        "ok": True,
        "symbol": sym,
        "verdict": record["verdict"],
        "verdict_num": record["verdict_num"],
        "pred_net": record.get("pred_net"),
        "prediction_run_id": record.get("prediction_run_id"),
    }


@app.post("/gom-verdict")
async def set_gom_verdict(payload: GomVerdictPayload, background_tasks: BackgroundTasks):
    """Stocke le verdict GOM KOLA + indicateurs (JSON MCP ou bridge).
    Répond immédiatement pour ne pas bloquer le poller — le reste en background."""
    sym = _resolve_symbol(payload.symbol)
    # Stockage synchrone minimal — juste le strict nécessaire pour que le GET soit à jour
    sym_full, record = _gom_verdict_record_from_payload(payload, enrich_mt5=False)
    _GOM_VERDICT_STORE[sym_full] = record

    # 🔑 INVALIDATE gom-kola-dashboard cache so SMC_Universal sees fresh verdict immediately
    for chart_tf in ["M1", "M5", "M15", "H1", "H4", "D1"]:
        cache_key = f"{sym_full}:{chart_tf}"
        if cache_key in _gom_cache:
            del _gom_cache[cache_key]
    logger.info(f"[GOM-VERDICT] Cache invalidated for {sym_full} — SMC_Universal will poll fresh data next call")

    # Opérations lourdes (tableau sync, auto-trade) en arrière-plan
    background_tasks.add_task(_store_gom_verdict_payload_bg, payload)
    return {
        "ok": True,
        "symbol": sym_full,
        "verdict": record["verdict"],
        "verdict_num": record["verdict_num"],
        "pred_net": record.get("pred_net"),
        "path_guided": record.get("path_guided"),
    }


@app.post("/gom-verdict/webhook")
async def set_gom_verdict_webhook(request: Request):
    """Webhook TradingView — corps CSV Pine ou JSON."""
    raw = (await request.body()).decode("utf-8", errors="replace").strip()
    parsed = _parse_gom_tv_csv(raw)
    if not parsed:
        return {"ok": False, "error": "Invalid GOM alert body"}
    payload = GomVerdictPayload(**parsed)
    return _store_gom_verdict_payload(payload)

@app.post("/gom-prediction/bb-webhook")
async def gom_prediction_bb_webhook(request: Request):
    """Webhook prédictions Bollinger Bands (300 bougies) depuis Pine Script."""
    raw = (await request.body()).decode("utf-8", errors="replace").strip()
    # Format: "PRED_BB|CRASH_1000_INDEX|1|MID:[1,2,3]|UP:[1,2,3]|DN:[1,2,3]"
    try:
        parts = raw.split("|")
        if len(parts) < 5 or parts[0] != "PRED_BB":
            return {"ok": False, "error": "Invalid prediction format"}

        symbol = _resolve_symbol(parts[1])
        timeframe = parts[2]

        # Parser les données compactes
        pred_data = {}
        for i in range(3, len(parts)):
            if ":[" in parts[i]:
                key = parts[i].split(":")[0]
                vals_str = parts[i].split(":[")[1].rstrip("]")
                vals = [float(v.strip()) for v in vals_str.split(",") if v.strip()]
                pred_data[key] = vals

        # Stocker temporairement (clé: symbol + timeframe)
        cache_key = f"{symbol}_{timeframe}_pred_bb"
        _GOM_VERDICT_STORE[cache_key] = {
            "pred_bb_mid": pred_data.get("MID", []),
            "pred_bb_up": pred_data.get("UP", []),
            "pred_bb_dn": pred_data.get("DN", []),
            "timestamp": datetime.utcnow().isoformat(),
            "symbol": symbol,
            "timeframe": timeframe,
        }

        logger.info(f"[GOM-Pred] Stored BB predictions for {symbol} {timeframe}: {len(pred_data.get('MID', []))} points")
        return {"ok": True, "symbol": symbol, "points": len(pred_data.get("MID", [])), "message": "BB predictions stored"}
    except Exception as e:
        logger.error(f"[GOM-Pred] Error parsing prediction: {e}")
        return {"ok": False, "error": str(e)}

@app.get("/gom-prediction/bb")
async def get_gom_prediction_bb(symbol: str = "XAUUSD", timeframe: str = "1"):
    """Récupère les prédictions Bollinger Bands (300 bougies)."""
    sym = _resolve_symbol(symbol)
    cache_key = f"{sym}_{timeframe}_pred_bb"
    pred = _PENDING_ORDER_STORE.get(cache_key) or _GOM_VERDICT_STORE.get(cache_key)

    if not pred:
        return {"ok": False, "symbol": sym, "timeframe": timeframe, "message": "No BB predictions available"}

    return {
        "ok": True,
        "symbol": sym,
        "timeframe": timeframe,
        "pred_bb_mid": pred.get("pred_bb_mid", []),
        "pred_bb_up": pred.get("pred_bb_up", []),
        "pred_bb_dn": pred.get("pred_bb_dn", []),
        "count": len(pred.get("pred_bb_mid", [])),
        "timestamp": pred.get("timestamp"),
    }

