@app.get("/gom-verdict")
async def get_gom_verdict(
    symbol: str = "XAUUSD",
    chart_tf: str = "M15",
    source: str = "auto",
):
    """Retourne le verdict GOM — connecteur TV en priorité (source=tv|auto)."""
    sym = _resolve_symbol(symbol)

    try:
        dash = _resolve_gom_dashboard(sym, chart_tf, source)
        if dash.get("ok"):
            try:
                flat = _build_gom_mt5_payload(dash)
            except Exception as map_err:
                logger.warning(f"[GOM-Verdict] payload map failed for {sym}: {map_err}")
                flat = dash
            flat["data_source"] = dash.get("data_source", "live_calculation")
            flat["timestamp"] = dash.get("timestamp")
            return {"ok": True, "symbol": sym, **flat}
    except Exception as e:
        logger.warning(f"[GOM-Verdict] resolve failed for {sym}: {e}")

    # FALLBACK: gom_signal.json (legacy)
    verdict = None
    try:
        gom_file = Path(__file__).resolve().parent / "data" / "gom_signal.json"
        if gom_file.is_file():
            data = json.loads(gom_file.read_text(encoding="utf-8"))
            if isinstance(data, dict) and sym in data:
                verdict = data[sym]
    except Exception:
        verdict = None

    if not verdict:
        verdict = _lookup_gom_store(sym, _GOM_VERDICT_STORE)

    if not verdict:
        return {"ok": False, "symbol": sym, "verdict": None, "message": "Aucun verdict GOM — uploader candles MT5"}

    # ✅ MAP entry→setup_entry, sl→setup_sl, tp→setup_tp1 (from gom_signal.json)
    # Force le mapping même si setup_* existent déjà
    if not verdict.get("setup_entry") and verdict.get("entry"):
        verdict["setup_entry"] = verdict["entry"]
    if not verdict.get("setup_sl") and verdict.get("sl"):
        verdict["setup_sl"] = verdict["sl"]
    if not verdict.get("setup_tp1") and verdict.get("tp"):
        verdict["setup_tp1"] = verdict["tp"]

    logger.info(f"[GET-Verdict] {sym} après mapping: entry={verdict.get('entry')}, setup_entry={verdict.get('setup_entry')}, setup_sl={verdict.get('setup_sl')}, setup_tp1={verdict.get('setup_tp1')}")

    # DEBUG: log predictions
    if verdict.get("pred_bb_mid"):
        logger.info(f"[GET-Verdict] {sym}: found {len(verdict.get('pred_bb_mid', []))} predictions")
    # Retourner ok:false si WAIT sans scores — poller non actif ou TV sans GOM visible
    if (verdict.get("verdict_num", 0) == 0
            and float(verdict.get("score_buy") or 0) == 0
            and float(verdict.get("score_sell") or 0) == 0):
        return {"ok": False, "symbol": sym, "verdict": "WAIT",
                "message": "GOM stale — is gom_verdict_poller running?"}
    # DISABLED: staleness check was too strict, MT5 needs to accept old but valid verdicts
    # try:
    #     age = (datetime.utcnow() - datetime.fromisoformat(verdict["timestamp"])).total_seconds()
    #     if age > 900:
    #         return {"ok": False, "symbol": sym, "verdict": verdict.get("verdict"),
    #                 "message": f"GOM stale ({int(age)}s) — relancer gom_verdict_poller.py"}
    # except Exception:
    #     pass
    flat = _build_gom_mt5_payload(verdict)
    return {"ok": True, "symbol": sym, **flat}

def _calculate_gom_verdict(score_buy: float, score_sell: float, coherence: float = 0, filter_ratio: float = 0) -> tuple:
    """
    Calcule le verdict GOM basé sur les scores.
    Retourne: (verdict_num, verdict_string)

    verdict_num:
      3 = PERFECT BUY
      2 = GOOD BUY
      1 = BUY
      0 = WAIT
     -1 = SELL
     -2 = GOOD SELL
     -3 = PERFECT SELL
    """
    gap = abs(score_buy - score_sell)

    # Gating: coherence et filter_ratio doivent être >= 0.40 pour un signal
    if coherence is None or filter_ratio is None or (coherence < 0.40 and filter_ratio < 0.40):
        return (0, "WAIT")

    # Classification par gap
    if gap < 1.2:
        return (0, "WAIT")
    elif 1.2 <= gap < 2.5:
        if score_buy > score_sell:
            return (1, "BUY")
        else:
            return (-1, "SELL")
    elif 2.5 <= gap < 4.0:
        if score_buy > score_sell:
            return (2, "GOOD BUY")
        else:
            return (-2, "GOOD SELL")
    else:  # gap >= 4.0
        if score_buy > score_sell:
            return (3, "PERFECT BUY")
        else:
            return (-3, "PERFECT SELL")

@app.get("/gom-verdicts")
async def get_all_gom_verdicts():
    """
    Retourne TOUS les verdicts GOM.
    Priorité : _GOM_VERDICT_STORE (données MT5 live fraîches du poller).
    Fallback : gom_signal.json pour les symboles absents du store.
    """
    try:
        def _build_verdict_obj(symbol: str, record: dict) -> dict:
            score_buy = float(record.get("score_buy") or 0)
            score_sell = float(record.get("score_sell") or 0)
            coherence_raw = float(record.get("coherence_pct") or 0)
            filter_ratio = float(record.get("filter_ratio") or 0)

            # Priorité absolue au verdict_num déjà calculé (poller MT5 ou _gom_verdict_record_from_payload)
            # Le recalcul via _calculate_gom_verdict n'est qu'un fallback pour les records sans verdict_num
            stored_vn = record.get("verdict_num")
            if stored_vn is not None and stored_vn != 0:
                vn = int(stored_vn)
                verdict_str = record.get("verdict", "WAIT")
            else:
                coherence = coherence_raw / 100.0 if coherence_raw > 1.0 else coherence_raw
                vn, verdict_str = _calculate_gom_verdict(score_buy, score_sell, coherence, filter_ratio)
                # Si le record a un verdict texte explicite mais vn=0 (ex: données file sans scores)
                # faire confiance au texte stocké et reconstruire le vn
                stored_verdict = (record.get("verdict") or "WAIT").upper()
                if stored_vn == 0 and stored_verdict not in ("WAIT", ""):
                    verdict_str = stored_verdict
                    if "PERFECT BUY" in stored_verdict: vn = 3
                    elif "GOOD BUY" in stored_verdict: vn = 2
                    elif stored_verdict == "BUY": vn = 1
                    elif "PERFECT SELL" in stored_verdict: vn = -3
                    elif "GOOD SELL" in stored_verdict: vn = -2
                    elif stored_verdict == "SELL": vn = -1

            entry = float(record.get("entry") or record.get("close") or record.get("price") or 0)
            sl = float(record.get("sl") or record.get("setup_sl") or 0)
            tp = float(record.get("tp") or record.get("setup_tp1") or 0)

            return {
                "symbol": symbol,
                "verdict_num": vn,
                "verdict": verdict_str,
                "score_buy": score_buy,
                "score_sell": score_sell,
                "verdict_gap": abs(score_buy - score_sell),
                "coherence_pct": coherence_raw,
                "filter_ratio": filter_ratio,
                "entry": entry,
                "sl": sl,
                "tp": tp,
                "setup_entry": float(record.get("setup_entry") or entry or 0),
                "setup_sl": float(record.get("setup_sl") or sl or 0),
                "setup_tp1": float(record.get("setup_tp1") or tp or 0),
                "timestamp": str(record.get("timestamp") or ""),
                "tf_global_dir": str(record.get("tf_global_dir") or "NEUT"),
                "tf_global_strength": int(record.get("tf_global_strength") or 0),
                "source": str(record.get("source") or "file"),
                # Directions par timeframe (pour affichage rapport + per-TF verdicts)
                "tf_m1_dir": str(record.get("tf_m1_dir") or "NEUT"),
                "tf_m1_rsi": int(record.get("tf_m1_rsi") or 50),
                "tf_m5_dir": str(record.get("tf_m5_dir") or "NEUT"),
                "tf_m5_rsi": int(record.get("tf_m5_rsi") or 50),
                "tf_m15_dir": str(record.get("tf_m15_dir") or "NEUT"),
                "tf_m15_rsi": int(record.get("tf_m15_rsi") or 50),
                "tf_h1_dir": str(record.get("tf_h1_dir") or "NEUT"),
                "tf_h1_rsi": int(record.get("tf_h1_rsi") or 50),
                "tf_h4_dir": str(record.get("tf_h4_dir") or "NEUT"),
                "tf_h4_rsi": int(record.get("tf_h4_rsi") or 50),
                "tf_d1_dir": str(record.get("tf_d1_dir") or "NEUT"),
                "tf_d1_rsi": int(record.get("tf_d1_rsi") or 50),
                "tf_w1_dir": str(record.get("tf_w1_dir") or "NEUT"),
            }

        verdicts = []
        seen_symbols: set = set()

        # 1. Priorité : store mémoire (données MT5 live du poller gom_mt5_poller.py)
        for sym, record in list(_GOM_VERDICT_STORE.items()):
            try:
                obj = _build_verdict_obj(sym, record)
                verdicts.append(obj)
                seen_symbols.add(sym.upper())
            except Exception as e:
                logger.warning(f"[GOM-Verdicts] Store error {sym}: {e}")

        # 2. Fallback fichier pour symboles absents du store
        gom_file = Path(__file__).resolve().parent / "data" / "gom_signal.json"
        if gom_file.is_file():
            try:
                file_data = json.loads(gom_file.read_text(encoding="utf-8"))
                for symbol, record in file_data.items():
                    if symbol.upper() in seen_symbols:
                        continue  # Déjà couvert par le store live
                    try:
                        obj = _build_verdict_obj(symbol, record)
                        obj["source"] = "file_fallback"
                        verdicts.append(obj)
                    except Exception as e:
                        logger.warning(f"[GOM-Verdicts] File error {symbol}: {e}")
            except Exception as e:
                logger.warning(f"[GOM-Verdicts] Cannot read gom_signal.json: {e}")

        verdicts.sort(key=lambda x: (-abs(x["verdict_num"]), -x["verdict_gap"]))

        live_count = sum(1 for v in verdicts if v.get("source", "") not in ("file", "file_fallback"))
        logger.info(f"[GOM-Verdicts] {len(verdicts)} verdicts ({live_count} live MT5, {len(verdicts)-live_count} fichier)")
        return {
            "ok": True,
            "count": len(verdicts),
            "live_count": live_count,
            "verdicts": verdicts,
            "timestamp": datetime.utcnow().isoformat()
        }

    except Exception as e:
        logger.error(f"[GOM-Verdicts] Error: {e}")
        return {
            "ok": False,
            "verdicts": [],
            "message": f"Error loading verdicts: {str(e)}"
        }

@app.get("/pending-order")
async def get_pending_order(symbol: str = "XAUUSD", peek: bool = False):
    """
    Retourne l'ordre pending pour un symbole.
    peek=true : lecture seule sans verrouillage (debug / admin).
    peek=false (défaut) : verrouille en 'executing' au premier poll — anti-duplication MT5.
    """
    sym = _resolve_symbol(symbol)
    order = _PENDING_ORDER_STORE.get(sym)
    if not order:
        order = _PENDING_ORDER_STORE.get(sym.upper())
    if not order:
        order = _PENDING_ORDER_STORE.get(sym.lower())
    if not order:
        sym_clean = sym.upper().replace(" ","").replace("INDEX","")
        for k, v in _PENDING_ORDER_STORE.items():
            if k.upper().replace(" ","").replace("INDEX","") == sym_clean:
                order = v
                break

    if not order:
        return {"ok": False, "symbol": sym, "order": None, "message": "Aucun ordre pending"}
    if order.get("status", "ready") == "conflict_pending":
        return {"ok": False, "symbol": sym, "order": None, "message": "Ordre en attente résolution conflit TA/TV"}

    if peek:
        return {"ok": True, "symbol": sym, "order": order}

    # 🔒 ANTI-DUPLICATION : marquer executing au premier poll, mais continuer
    # à retourner l'ordre pour que l'EA XAUUSD puisse l'exécuter.
    # La suppression définitive se fait via /pending-order/executed (après trade MT5 réel).
    # Ne plus bloquer avec ok=false en executing — plusieurs EA pollent le même symbole.
    if order.get("status") == "ready":
        order["status"] = "executing"

    return {"ok": True, "symbol": sym, "order": order}


@app.post("/pending-order/{symbol}/reset")
async def reset_pending_order_status(symbol: str):
    """
    Remet un ordre bloqué en 'executing' au statut 'ready' pour qu'il soit
    de nouveau proposé au TradeManager (ex : EA crashé avant d'avoir lu l'ordre).
    """
    sym = _resolve_symbol(symbol)
    async with _pending_orders_lock:
        order = _PENDING_ORDER_STORE.get(sym)
        if not order:
            # Chercher variantes
            sym_clean = sym.upper().replace(" ","").replace("INDEX","")
            for k, v in _PENDING_ORDER_STORE.items():
                if k.upper().replace(" ","").replace("INDEX","") == sym_clean:
                    order = v
                    sym = k
                    break
        if not order:
            return {"ok": False, "symbol": sym, "message": "Aucun ordre pending trouvé"}
        prev = order.get("status")
        order["status"] = "ready"
        await _pending_orders_save()
        logger.info(f"[PendingOrder] {sym} reset {prev} → ready")
        return {"ok": True, "symbol": sym, "previous_status": prev, "new_status": "ready"}


@app.post("/pending-order/executed")
async def mark_pending_order_executed(payload: dict = Body(...)):
    """TradeManager appelle cet endpoint après avoir placé le trade.
    Supprime l'ordre du store pour éviter toute ré-exécution.
    payload: {symbol: str, mt5_ticket: int}
    """
    sym    = _resolve_symbol((payload.get("symbol") or "").strip().upper())
    ticket = payload.get("mt5_ticket")
    order  = _PENDING_ORDER_STORE.pop(sym, None)
    if not order:
        # Chercher avec variantes
        for k in list(_PENDING_ORDER_STORE.keys()):
            if k.upper().replace(" ","").replace("INDEX","") == sym.upper().replace(" ","").replace("INDEX",""):
                order = _PENDING_ORDER_STORE.pop(k, None)
                break
    if order:
        logger.info(f"[PendingOrder] {sym} exécuté ticket={ticket} → supprimé du store")
        if (order.get("source") or "") == "pipeline":
            import time as _time
            _PIPELINE_LAST_EXEC[sym] = _time.time()
            logger.info(f"[PendingOrder] {sym} pipeline cooldown {PIPELINE_GOM_COOLDOWN_SEC}s activé")

        # Enregistrer perte ou gain — tracker win streak global
        trade_profit = payload.get("profit") or payload.get("pnl") or 0
        try:
            trade_profit = float(trade_profit)
        except (TypeError, ValueError):
            trade_profit = 0

        import time as _time2
        global _WIN_STREAK, _WIN_STREAK_PAUSE_UNTIL

        if trade_profit < 0:
            _LOSS_COOLDOWN_STORE[sym] = _time2.time()
            logger.warning(f"[PendingOrder] {sym} perte enregistrée (profit={trade_profit}) → cooldown {LOSS_COOLDOWN_SEC//60}min activé")
            _record_win_streak_from_profit(trade_profit, sym)

        elif trade_profit > 0:
            _record_win_streak_from_profit(trade_profit, sym)

        return {"ok": True, "symbol": sym, "removed": True}
    return {"ok": True, "symbol": sym, "removed": False}


@app.get("/pending-orders")
async def list_pending_orders():
    """Liste tous les ordres status=ready (TradeManager poll multi-symboles)."""
    ready = [
        o for o in _PENDING_ORDER_STORE.values()
        if (o.get("status") or "ready").lower() in ("ready",)
    ]
    return {"ok": True, "count": len(ready), "orders": ready}


@app.get("/trading-pause")
async def get_trading_pause():
    """
    Retourne l'état de la pause globale post-win-streak.
    active=true  → pipeline ne doit pas placer d'ordres
    active=false → trading autorisé
    """
    import time as _tp
    now = _tp.time()
    is_paused = now < _WIN_STREAK_PAUSE_UNTIL
    remaining_sec = max(0, int(_WIN_STREAK_PAUSE_UNTIL - now))
    return {
        "active": is_paused,
        "pause_until": _WIN_STREAK_PAUSE_UNTIL if is_paused else None,
        "remaining_sec": remaining_sec,
        "win_streak_current": len(_WIN_STREAK),
        "win_streak_threshold": WIN_STREAK_THRESHOLD,
        "win_streak_pause_hours": WIN_STREAK_PAUSE_SEC // 3600,
        "min_entry_probability_pct": MIN_ENTRY_PROBABILITY_PCT,
    }


@app.post("/pending-order/resolve")
async def resolve_pending_order(payload: dict = Body(...)):
    """Promeut un ordre CONFLICT_PENDING en ready — appelé par le bridge quand TV s'aligne."""
    sym = _resolve_symbol((payload.get("symbol") or "XAUUSD").strip().upper())
    order = _PENDING_ORDER_STORE.get(sym)
    if not order:
        return {"ok": False, "symbol": sym, "message": "Aucun ordre pending"}
    order["status"] = "ready"
    logger.info(f"[PendingOrder] {sym} conflit résolu → status=ready")
    return {"ok": True, "symbol": sym, "status": "ready"}

# ── Approval store (pipeline avec validation WhatsApp) ──────────────────────
# key = symbol | value = {"answer": "yes"|"no"|None, "ts": float}
_APPROVAL_STORE: Dict[str, dict] = {}

@app.post("/approval")
async def post_approval(payload: dict = Body(...)):
    """Enregistre la réponse OUI/NON de l'utilisateur pour un symbole.
    Appelé par PsychoBot quand l'utilisateur répond au message de validation.
    payload: {symbol: str, answer: "yes"|"no"}
    """
    sym    = _resolve_symbol((payload.get("symbol") or "").strip().upper())
    answer = str(payload.get("answer") or "").strip().lower()
    if answer in ("oui", "yes", "o", "y", "1", "ok", "go", "valider"):
        answer = "yes"
    elif answer in ("non", "no", "n", "0", "skip", "annuler"):
        answer = "no"
    else:
        return {"ok": False, "message": f"Réponse non reconnue: {answer}. Utilisez yes/no"}
    _APPROVAL_STORE[sym] = {"answer": answer, "ts": time.time()}
    logger.info(f"[Approval] {sym} → {answer}")
    return {"ok": True, "symbol": sym, "answer": answer}

@app.get("/approval/{symbol}")
async def get_approval(symbol: str):
    """Retourne la réponse enregistrée pour un symbole (poll par le pipeline)."""
    sym  = _resolve_symbol(symbol.strip().upper())
    data = _APPROVAL_STORE.get(sym)
    if not data:
        return {"ok": True, "symbol": sym, "answer": None, "pending": True}
    return {"ok": True, "symbol": sym, "answer": data["answer"], "pending": False, "ts": data["ts"]}

@app.delete("/approval/{symbol}")
async def delete_approval(symbol: str):
    """Supprime l'approbation après traitement."""
    sym = _resolve_symbol(symbol.strip().upper())
    _APPROVAL_STORE.pop(sym, None)
    return {"ok": True, "symbol": sym}

@app.delete("/pending-order")
async def delete_pending_order(symbol: str = "XAUUSD"):
    sym = _resolve_symbol(symbol)
    removed = _PENDING_ORDER_STORE.pop(sym, None)
    return {"ok": True, "symbol": sym, "removed": removed is not None}


