# ═══════════════════════════════════════════════════════════════════
# GOM KOLA DASHBOARD — Real-time TradingView tableau sync
# ═══════════════════════════════════════════════════════════════════

_GOM_TABLEAU_STORE = {}  # {symbol: {timeframes, verdict, timestamp}}
_GOM_TABLEAU_LOCK = asyncio.Lock()

class GomTableauBody(BaseModel):
    symbol: str
    gom_data: dict


def _normalize_tableau_timeframes(tfs) -> dict:
    """Convertit liste [{tf, direction, rsi}] ou dict nested vers {M1: {direction, rsi}, ...}."""
    if isinstance(tfs, dict):
        out = {}
        for k, v in tfs.items():
            key = str(k).upper()
            if isinstance(v, dict):
                out[key] = {
                    "direction": v.get("direction", v.get("dir", "")),
                    "rsi": v.get("rsi", 0),
                    "strength": v.get("strength", 0),
                }
            else:
                out[key] = {"direction": str(v), "rsi": 0}
        return out
    if isinstance(tfs, list):
        out = {}
        for item in tfs:
            if not isinstance(item, dict):
                continue
            key = str(item.get("tf", "")).upper()
            if not key:
                continue
            rsi_raw = item.get("rsi", 0)
            try:
                rsi_val = int(float(str(rsi_raw).replace(",", ".")))
            except (TypeError, ValueError):
                rsi_val = 0
            out[key] = {
                "direction": str(item.get("direction", item.get("dir", ""))),
                "rsi": rsi_val,
            }
        return out
    return {}


@app.post("/gom-tableau")
async def store_gom_tableau(body: GomTableauBody):
    """
    Reçoit les données GOM KOLA depuis gom_dashboard_sync.py.
    Stocke pour accès par TradeManager et autres clients.
    """
    try:
        sym = _resolve_symbol(body.symbol)
        gom_data = body.gom_data or {}
        tfs = _normalize_tableau_timeframes(gom_data.get("timeframes", {}))

        async with _GOM_TABLEAU_LOCK:
            _GOM_TABLEAU_STORE[sym] = {
                "timeframes": tfs,
                "verdict": gom_data.get("verdict", {}),
                "timestamp": gom_data.get("timestamp", datetime.utcnow().isoformat()),
            }

        return {"ok": True, "symbol": sym, "stored": True}

    except Exception as e:
        logger.error(f"Error storing GOM tableau: {e}")
        return {"ok": False, "error": str(e)}


@app.get("/gom-tableau")
async def get_gom_tableau(symbol: str = "XAUUSD"):
    """
    Récupère le dernier tableau GOM KOLA stocké.
    Utilisé par TradeManager pour affichage dashboard en temps réel.
    """
    try:
        sym = symbol.upper().strip()

        async with _GOM_TABLEAU_LOCK:
            data = _GOM_TABLEAU_STORE.get(sym)

        if not data:
            return {
                "ok": False,
                "symbol": sym,
                "error": "No GOM tableau data available"
            }

        return {
            "ok": True,
            "symbol": sym,
            "timeframes": data.get("timeframes", []),
            "verdict": data.get("verdict", {}),
            "timestamp": data.get("timestamp"),
            "age_seconds": (datetime.utcnow() - datetime.fromisoformat(data.get("timestamp", datetime.utcnow().isoformat()))).total_seconds()
        }

    except Exception as e:
        logger.error(f"Error retrieving GOM tableau: {e}")
        return {"ok": False, "error": str(e)}


@app.get("/gom-tableau-complete")
async def get_gom_tableau_complete(symbol: str = "XAUUSD"):
    """
    Récupère TOUTES les données GOM: multi-TF, verdict, zones, niveaux KOLA.
    Format optimisé pour MT5 dashboard (structure plate avec tous les champs).
    """
    try:
        sym = _resolve_symbol(symbol)

        # Récupérer les données sans lock (simple dict access)
        tableau_data = _lookup_gom_store(sym, _GOM_TABLEAU_STORE) or {}
        verdict_data = _lookup_gom_store(sym, _GOM_VERDICT_STORE) or {}

        if not tableau_data and not verdict_data:
            return {
                "ok": False,
                "symbol": sym,
                "error": "No GOM data available"
            }

        # Rejeter si données trop vieilles (> 2 min) — TV/poller déconnecté
        _ts_str = verdict_data.get("timestamp") or tableau_data.get("timestamp")
        if _ts_str:
            try:
                _age = (datetime.utcnow() - datetime.fromisoformat(_ts_str)).total_seconds()
                if _age > 120:
                    return {
                        "ok": False, "symbol": sym,
                        "error": f"GOM stale ({int(_age)}s) — relancer gom_verdict_poller.py"
                    }
            except Exception:
                pass

        # Rejeter si le seul verdict stocké est WAIT avec scores à zéro — poller arrêté
        v_num = verdict_data.get("verdict_num", 0)
        v_buy = float(verdict_data.get("score_buy") or 0)
        v_sell = float(verdict_data.get("score_sell") or 0)
        if not tableau_data and v_num == 0 and v_buy == 0 and v_sell == 0:
            return {
                "ok": False,
                "symbol": sym,
                "error": "GOM data stale (WAIT with no scores — is gom_verdict_poller running?)"
            }

        # Helper pour accéder nested dict en sécurité
        def safe_get(d, *keys, default=None):
            for key in keys:
                if isinstance(d, dict):
                    d = d.get(key, {})
                else:
                    return default
            return d if d else default

        # Construire la structure complète pour dashboard MT5 (lecture cache — pas de MT5 sync)
        base = _build_gom_mt5_payload(verdict_data) if verdict_data else {}
        complete_data = {
            "ok": True,
            "symbol": sym,
            "capture_time": datetime.utcnow().isoformat(),
            **base,
            "force_pts": base.get("verdict_gap", 0),
            "rsi_alert": safe_get(tableau_data, "verdict", "rsi_alert", default=""),
            "kola_line_1": tableau_data.get("kola_lines", [0, 0])[0] if tableau_data.get("kola_lines") and len(tableau_data.get("kola_lines", [])) > 0 else 0,
            "kola_line_2": tableau_data.get("kola_lines", [0, 0])[1] if tableau_data.get("kola_lines") and len(tableau_data.get("kola_lines", [])) > 1 else 0,
            "zone_1_high": tableau_data.get("zones", [{}])[0].get("high", 0) if tableau_data.get("zones") and len(tableau_data.get("zones", [])) > 0 else 0,
            "zone_1_low": tableau_data.get("zones", [{}])[0].get("low", 0) if tableau_data.get("zones") and len(tableau_data.get("zones", [])) > 0 else 0,
            "zone_2_high": tableau_data.get("zones", [{}])[1].get("high", 0) if tableau_data.get("zones") and len(tableau_data.get("zones", [])) > 1 else 0,
            "zone_2_low": tableau_data.get("zones", [{}])[1].get("low", 0) if tableau_data.get("zones") and len(tableau_data.get("zones", [])) > 1 else 0,
        }

        # TF depuis tableau MCP si absent du verdict store
        for lk, label in (
            ("m1", "M1"), ("m5", "M5"), ("m15", "M15"), ("h1", "H1"),
            ("h4", "H4"), ("d1", "D1"), ("w1", "W1"), ("global", "GLOBAL"),
        ):
            dk = f"tf_{lk}_dir"
            rk = f"tf_{lk}_rsi" if lk != "global" else None
            if not complete_data.get(dk):
                merged = _normalize_tf_dir_label(
                    safe_get(tableau_data, "timeframes", label, "direction", default="")
                )
                if merged:
                    complete_data[dk] = merged
            else:
                complete_data[dk] = _normalize_tf_dir_label(complete_data.get(dk))
            if rk and not complete_data.get(rk):
                complete_data[rk] = safe_get(tableau_data, "timeframes", label, "rsi", default=0)
            if lk == "global" and not complete_data.get("tf_global_strength"):
                complete_data["tf_global_strength"] = safe_get(
                    tableau_data, "timeframes", "GLOBAL", "strength", default=0
                )

        return complete_data

    except Exception as e:
        logger.error(f"Error in /gom-tableau-complete: {e}", exc_info=True)
        return {"ok": False, "symbol": symbol, "error": str(e)}


# ═══════════════════════════════════════════════════════════════════
# BRIDGE — MCP Watchlist Scan (appel depuis morning_scan_report.py)
# ═══════════════════════════════════════════════════════════════════

class BridgeMcpScanBody(BaseModel):
    symbols: List[str]

@app.post("/bridge/mcp-watchlist-scan")
async def bridge_mcp_watchlist_scan(body: BridgeMcpScanBody):
    """
    Orchestre le scan multi-symboles: ML predict + AutoScan par symbole.
    Retourne les résultats au format attendu par MorningScanReportGenerator.normalize_result().
    N'effectue pas d'appels HTTP internes pour éviter les deadlocks — lit directement les stores.
    """
    results = []
    for symbol in body.symbols[:25]:
        try:
            sym_clean = symbol.upper().strip()
            entry_price   = None
            current_price = 0.0
            stop_loss     = None
            take_profit   = None
            atr_val       = None
            confluence    = 0.0
            direction     = "NEUTRAL"
            reasons: List[str] = []

            # ── Session bias stocké sur fichier (mis à jour par bridge ou GOM poller) ──
            try:
                store = _read_session_bias_store()
                bias_data = store.get(sym_clean, {})
                if bias_data.get("direction") in ("BUY", "SELL"):
                    bias_dir  = bias_data["direction"]
                    bias_conf = float(bias_data.get("confidence", 0.5))
                    direction = bias_dir
                    confluence += bias_conf * 4
                    reasons.append(f"Bias:{bias_dir}({bias_conf:.0%})")
            except Exception:
                pass

            # ── GOM verdict (mis à jour par gom_verdict_poller) ──
            try:
                gom = _GOM_VERDICT_STORE.get(sym_clean, {})
                gom_v = str(gom.get("verdict", "")).upper()
                if gom_v in ("BUY", "GOOD BUY", "PERFECT BUY"):
                    gv_dir  = "BUY"
                    gv_conf = 0.7 if "PERFECT" in gom_v else 0.55
                    if direction == "NEUTRAL":
                        direction = gv_dir
                    if gv_dir == direction:
                        confluence += gv_conf * 3
                        reasons.append(f"GOM:{gom_v}")
                    else:
                        confluence -= 1.0
                elif gom_v in ("SELL", "GOOD SELL", "PERFECT SELL"):
                    gv_dir  = "SELL"
                    gv_conf = 0.7 if "PERFECT" in gom_v else 0.55
                    if direction == "NEUTRAL":
                        direction = gv_dir
                    if gv_dir == direction:
                        confluence += gv_conf * 3
                        reasons.append(f"GOM:{gom_v}")
                    else:
                        confluence -= 1.0
                if gom.get("setup_entry"):
                    entry_price = float(gom["setup_entry"])
                if gom.get("setup_sl"):
                    stop_loss = float(gom["setup_sl"])
                if gom.get("setup_tp1"):
                    take_profit = float(gom["setup_tp1"])
            except Exception:
                pass

            # ── ATR SL/TP auto si manquants ──
            if direction in ("BUY", "SELL") and atr_val and not stop_loss:
                cp = entry_price or current_price
                if cp and cp > 0:
                    entry_price = entry_price or cp
                    stop_loss   = round(cp - atr_val * 1.5, 5) if direction == "BUY" else round(cp + atr_val * 1.5, 5)
                    take_profit = round(cp + atr_val * 3.0, 5) if direction == "BUY" else round(cp - atr_val * 3.0, 5)

            confluence = min(round(confluence, 2), 10.0)

            results.append({
                "symbol":        sym_clean,
                "success":       True,
                "current_price": current_price,
                "bias":          {"direction": direction, "score": confluence, "reasons": reasons},
                "entry_setup":   {
                    "valid":            direction in ("BUY", "SELL") and confluence >= 4.0,
                    "confluence_score": confluence,
                    "direction":        direction,
                    "entry_price":      entry_price,
                    "stop_loss":        stop_loss,
                    "take_profit":      take_profit,
                    "atr":              atr_val,
                },
            })
        except Exception as e:
            results.append({"symbol": symbol, "success": False, "error": str(e)})

    return {"ok": True, "count": len(results), "all_results": results}


@app.post("/bridge/mcp-study-values")
async def bridge_mcp_study_values(body: dict = Body(default={})):
    """
    Retourne les study values GOM KOLA SIDO depuis le store en mémoire (_GOM_VERDICT_STORE).
    Utilisé par gom_verdict_poller._read_via_mcp_bridge() pour lire les plots Pine sans CLI Node.
    Format de retour identique à data_get_study_values MCP.
    """
    sym = _resolve_symbol((body.get("symbol") or "XAUUSD").strip().upper())
    record = _GOM_VERDICT_STORE.get(sym, {})
    if not record:
        return {"success": False, "study_count": 0, "studies": [], "message": "Aucun verdict GOM en cache"}
    # Convertir le record stocké en format study values attendu par parse_gom_study
    values = {
        "score_buy":          record.get("score_buy", 0),
        "score_sell":         record.get("score_sell", 0),
        "verdict_num":        record.get("verdict_num", 0),
        "verdict_gap":        record.get("verdict_gap"),
        "spike_pct":          record.get("spike_pct", 0),
        "rsi":                record.get("rsi"),
        "st_dir":             record.get("st_dir"),
        "entry_quality":      record.get("entry_quality"),
        "coherence_pct":      record.get("coherence_pct"),
        "kola_buy":           record.get("kola_buy"),
        "kola_sell":          record.get("kola_sell"),
        "bb_up":              record.get("bb_up"),
        "bb_mid":             record.get("bb_mid"),
        "bb_dn":              record.get("bb_dn"),
        "st_line":            record.get("st_line"),
        "vwap":               record.get("vwap"),
        "tf_global_dir":      record.get("tf_global_dir"),
        "tf_global_strength": record.get("tf_global_strength"),
        "tf_bull_count":      record.get("tf_bull_count"),
        "tf_bear_count":      record.get("tf_bear_count"),
        "pred_bull":          record.get("pred_bull"),
        "pred_bear":          record.get("pred_bear"),
        "pred_neut":          record.get("pred_neut"),
        "pred_net":           record.get("pred_net"),
        "setup_dir":          record.get("setup_dir", 0),
        "setup_entry":        record.get("setup_entry", 0),
        "setup_sl":           record.get("setup_sl", 0),
        "setup_tp1":          record.get("setup_tp1", 0),
        "setup_tp2":          record.get("setup_tp2", 0),
        "setup_rr":           record.get("setup_rr", 0),
        "setup_confirm_code": 1 if record.get("setup_confirm") == "PIN_BAR_BULL" else (-1 if record.get("setup_confirm") == "PIN_BAR_BEAR" else 0),
    }
    return {
        "success": True,
        "study_count": 1,
        "studies": [{"name": "GOM KOLA SIDO — Full Integration", "values": values}],
        "source": "gom_verdict_store",
        "timestamp": record.get("timestamp"),
    }


